function busy(text='\u0417\u0430\u0433\u0440\u0443\u0437\u043a\u0430...'){let old=document.getElementById('rtmBusy'); if(old)old.remove(); let el=document.createElement('div'); el.id='rtmBusy'; el.className='loading-overlay'; el.textContent=text; document.body.appendChild(el); document.body.classList.add('is-busy')}
function idle(){let el=document.getElementById('rtmBusy'); if(el)el.remove(); document.body.classList.remove('is-busy')}
function toast(text){let old=document.getElementById('rtmToast'); if(old)old.remove(); let el=document.createElement('div'); el.id='rtmToast'; el.className='toast'; el.textContent=text; document.body.appendChild(el); setTimeout(()=>el.remove(),2600)}
function updateSyncButton(){let b=$('#globalSyncBtn'); if(!b)return; b.textContent=state.syncing?'Синхронизация...':(state.lastSyncAt?'Синхронизация '+new Date(state.lastSyncAt).toLocaleTimeString('ru-RU',{hour:'2-digit',minute:'2-digit'}):'Синхронизация')}
async function ensureOnce(){if(schemaChecked)return;busy('Проверяю хранилища...');try{await ensureAll();schemaChecked=true;localStorage.setItem('rtm_obuchenie_schema_v045','ok')}finally{idle()}}
async function refreshItemsOnly(){state.items=await get(E.items); state.assigns=await get(E.assigns); state.progress=await get(E.progress); state.events=await get(E.events); state.attempts=await get(E.attempts); state.canvas=await get(E.canvas); renderAll();}
function debounceSave(key,fn,delay=700){clearTimeout(saveTimers[key]); saveTimers[key]=setTimeout(()=>fn().catch(e=>console.warn(e)),delay)}
function upsertLocalProject(id,name,props){let obj={ID:String(id),NAME:name,PROPERTY_VALUES:props,DATE_CREATE:now()}; state.projects.unshift(obj); return obj}
function shellLayout(){let shell=document.querySelector('.admin-shell'); if(!shell)return; let hasProjects=state.mode==='admin' && state.aview==='materials'; shell.classList.toggle('with-projects',hasProjects); shell.classList.toggle('no-projects',!hasProjects); document.getElementById('projectsPanel').style.display=hasProjects?'block':'none'}
const $=s=>document.querySelector(s), $$=s=>[...document.querySelectorAll(s)];
function log(x){console.log(x)}
function call(m,p={}){return new Promise((res,rej)=>BX24.callMethod(m,p,r=>r.error()?rej(new Error(r.error()+': '+r.error_description())):res(r.data())))}
async function ent(code,name,props){let exists=true;try{await call('entity.get',{ENTITY:code})}catch(error){if(/ENTITY_NOT_FOUND|Entity not found/i.test(String(error.message||error)))exists=false;else throw error}if(!exists){await call('entity.add',{ENTITY:code,NAME:name,ACCESS:{AU:'W'}});await call('entity.get',{ENTITY:code})}let raw=await call('entity.item.property.get',{ENTITY:code}),existing=Array.isArray(raw)?raw:(raw&&Array.isArray(raw.result)?raw.result:[]),known=new Set(existing.map(row=>String(row.PROPERTY||row.property||'')));for(const p of props){if(known.has(String(p[0])))continue;await call('entity.item.property.add',{ENTITY:code,PROPERTY:p[0],NAME:p[1],TYPE:'S',SORT:100});known.add(String(p[0]))}return true}
async function add(entity,name,props){try{return await addRaw(entity,name,props)}catch(e){if(String(e.message).includes('ERROR_ENTITY_NOT_FOUND')||String(e.message).includes('Entity not found')){localStorage.removeItem('rtm_obuchenie_schema_v045');schemaChecked=false;await ensureOnce();return await addRaw(entity,name,props)}throw e}}
async function findCreated(entity,name,props){let rows=await get(entity), stamp=props?.updatedAt; return rows.find(x=>x.NAME===name && (!stamp || x.PROPERTY_VALUES?.updatedAt===stamp))||rows.find(x=>x.NAME===name)}
async function upd(entity,id,name,props){return await call('entity.item.update',{ENTITY:entity,ID:id,NAME:name,PROPERTY_VALUES:props})}
function isAlreadyDeletedError(error){let text=String(error&&((error.error||'')+' '+(error.error_description||'')+' '+(error.message||''))||error||'').toUpperCase(); return text.includes('ERROR_ITEM_NOT_FOUND')||text.includes('ERROR_ENTITY_ITEM_NOT_FOUND')||text.includes('ERROR_NOT_FOUND')||text.includes('ITEM NOT FOUND')||text.includes('COULD NOT FIND ENTITY WITH ID')}
async function del(entity,id){try{return await call('entity.item.delete',{ENTITY:entity,ID:id})}catch(error){if(isAlreadyDeletedError(error))return {alreadyDeleted:true};throw error}}
function switchAdmin(v){state.aview=v; $$('.rail-btn').forEach(x=>x.classList.toggle('active',x.dataset.adminView===v)); $$('.admin-view').forEach(x=>x.classList.remove('active')); $('#admin'+cap(v)).classList.add('active'); shellLayout(); renderAll();}
function renderEvents(){let q=($('#eventSearch')?.value||'').toLowerCase(); let evs=state.events.filter(e=>(eventUserName(e)+' '+(e.PROPERTY_VALUES?.event||'')+' '+(e.PROPERTY_VALUES?.targetName||'')).toLowerCase().includes(q)); $('#eventsTotal').textContent='Всего: '+evs.length; $('#eventsTable').innerHTML=evs.map(e=>'<tr><td>'+fmt(e.PROPERTY_VALUES.createdAt)+'</td><td><a>'+esc(eventUserName(e))+'</a></td><td>'+esc(e.PROPERTY_VALUES.event||'—')+'</td><td><a>'+esc(typeLabel(findItem(e.PROPERTY_VALUES.targetId)?.PROPERTY_VALUES?.type)||'Материал')+': '+esc(e.PROPERTY_VALUES.targetName||'—')+'</a></td><td>'+esc(e.PROPERTY_VALUES.duration||'—')+'</td></tr>').join('')||'<tr><td colspan="5">Событий нет</td></tr>'}
function targetPoints(id){let it=findItem(id); if(!it)return 0; let meta=j(it.PROPERTY_VALUES?.meta); return Math.max(0,Number(meta.points||0))}
function userIdAliases(uid){let aliases=new Set([String(uid||'')]); try{let cur=currentUserId(), eff=effectiveUserId(); if(String(uid)===cur||String(uid)===eff||String(uid)==='0'){aliases.add(cur); aliases.add(eff)}}catch{} return aliases}
function userCompletedRows(uid){let seen=new Set(), users=userIdAliases(uid); return state.progress.filter(p=>users.has(String(p.PROPERTY_VALUES?.userId))&&p.PROPERTY_VALUES?.status==='completed').filter(p=>{let key=String(p.PROPERTY_VALUES?.targetId); if(seen.has(key))return false; seen.add(key); return true})}
function userPoints(uid=effectiveUserId()){return userCompletedRows(uid).reduce((sum,p)=>sum+targetPoints(p.PROPERTY_VALUES?.targetId),0)}
function leaderboardRows(){let ids=new Set(); state.users.forEach(u=>ids.add(String(u.ID||0))); state.progress.forEach(p=>ids.add(String(p.PROPERTY_VALUES?.userId||0))); ids.add(currentUserId()); ids.add(effectiveUserId()); return [...ids].map(uid=>{let u=userById(uid); return {uid,name:u?fullName(u):userDisplayById(uid),points:userPoints(uid),done:userCompletedRows(uid).length}}).filter(r=>r.name&&r.name!=='ID ').sort((a,b)=>b.points-a.points||b.done-a.done).slice(0,10)}
function renderProfile(){let cs=assignedCourses(), done=cs.filter(c=>isDone(c.ID,'course')).length, uid=effectiveUserId(), completedRows=userCompletedRows(uid), points=userPoints(uid); $('#profActive').textContent=cs.length-done; $('#profCompleted').textContent=done; $('#profDone').textContent=completedRows.length; $('#profScore').textContent=points; let scoreLabel=$('#profScore')?.nextElementSibling; if(scoreLabel)scoreLabel.textContent='Очки'; let box=$('#profileLeaderboard'); if(box){let rows=leaderboardRows(); box.innerHTML='<div class="panel-head"><h3>Топ по очкам</h3><button id="profileTopRefresh">Обновить</button></div><div class="leaderboard-list">'+(rows.map((r,i)=>'<div class="leader-row"><b>'+(i+1)+'. '+esc(r.name)+'</b><span>'+r.points+' очков</span><small>'+r.done+' завершено</small></div>').join('')||'<p class="muted">Пока нет завершений</p>')+'</div>'; $('#profileTopRefresh').onclick=()=>loadAll(true)}}
function openItem(id){let it=findItem(id); if(!it)return; let kind=materialKind(it); if(kind==='folder'){state.editorReturnCourseId=null; state.folderId=String(id);renderMaterials();return} if(!it.PROPERTY_VALUES.parentId||String(it.PROPERTY_VALUES.parentId)==='root')state.editorReturnCourseId=null; if(kind==='course')openCourseEditor(id); else if(kind==='article')openArticleEditor(id); else if(kind==='test')openTestEditor(id); else alert('Файл: '+it.NAME);}
