function openCourseEditor(id){let c=findItem(id); if(!c){alert('Материал не найден. Обновляю данные.'); loadAll(); return;} state.courseId=String(c.ID); let meta=j(c.PROPERTY_VALUES.meta); showOnlyEditor('courseEditorView'); $('#courseEditorTitle').textContent=c.NAME; $('#courseNameInput').value=c.NAME; $('#courseDescInput').value=c.PROPERTY_VALUES.content||''; $('#coursePointsInput').value=meta.points||5; $('#courseCertificateInput').checked=!!meta.certificate; $('#courseSequentialInput').checked=!!meta.sequential; renderCourseEditor(); renderAssignUsers();}
function openArticleEditor(id){let a=findItem(id); if(!a){alert('Материал не найден. Обновляю данные.'); loadAll(); return;} state.articleId=String(a.ID); let meta=j(a.PROPERTY_VALUES.meta); if(!meta.pages)meta.pages=[{title:a.NAME,html:a.PROPERTY_VALUES.content||'<h1>'+esc(a.NAME)+'</h1><p><br></p>'}]; showOnlyEditor('articleEditorView'); $('#articleEditorTitle').textContent=a.NAME; $('#articleNameInput').value=a.NAME; $('#articleDescInput').value=meta.description||''; $('#articlePointsInput').value=meta.points||1; state.articlePage=0; switchTab('article','content'); renderArticlePages(); renderAssignmentPanel('article')}
function openTestEditor(id){let t=findItem(id); if(!t){alert('Материал не найден. Обновляю данные.'); loadAll(); return;} state.testId=String(t.ID); state.testEditorTab='questions'; showOnlyEditor('testEditorView'); $('#testEditorTitle').textContent=t.NAME; renderTestEditor(); let addBtn=$('#addQuestionBtn'); if(addBtn)addBtn.onclick=addQuestion; let pubBtn=$('#publishTestBtn'); if(pubBtn)pubBtn.onclick=publishTest; bindTestTabs()}
function openUserCourse(c){if(!c){showUserCourses(); return;} state.courseId=String(c.ID); $('#userCourseView')?.classList.add('reference-course-view'); $('#userCourseListView').classList.add('hidden'); $('#userCourseView').classList.remove('hidden'); $('#userMaterialView').classList.add('hidden'); $('#uCourseTitle').textContent=c.NAME; $('#uCourseDesc').textContent=c.PROPERTY_VALUES.content||''; let ass=assignment(c.ID), due=ass?.PROPERTY_VALUES?.dueAt; $('#uCourseDeadline').classList.toggle('hidden',!due); $('#uCourseDeadline').classList.toggle('overdue',isOverdue(c.ID)); $('#uCourseDeadline').textContent=due?'Дедлайн: '+fmt(due):''; let mats=courseMaterials(c.ID), done=mats.filter(m=>isDone(m.ID,materialKind(m))).length, pct=mats.length?Math.round(done/mats.length*100):0; let progressText=$('#uCourseProgressText'), progressBar=$('#uCourseProgress')?.closest('.progressbar'); if(progressText&&progressBar&&progressBar.previousElementSibling!==progressText)progressBar.parentNode.insertBefore(progressText,progressBar); $('#uCourseProgress').style.width=pct+'%'; progressText.innerHTML='<span>Прогресс курса</span><b>'+done+'/'+mats.length+' ('+pct+'%)</b>'; $('#uCourseStatus').textContent=isOverdue(c.ID)?'Просрочен':isDone(c.ID,'course')?'Завершен':pct?'В процессе':'Не начато'; $('#uCourseStructure').innerHTML=renderCourseStructureUser(c.ID); $('#uCourseTests').innerHTML=renderTestsUser(c.ID)}
function renderCourseStructureUser(cid){let c=findItem(cid), meta=j(c.PROPERTY_VALUES.meta), sections=meta.sections||[{id:'nosection',title:'Без секции',order:0}], mats=courseMaterials(cid); return '<div class="course-ref-list">'+sections.sort((a,b)=>(a.order||0)-(b.order||0)).map(sec=>{let rows=mats.filter(m=>(j(m.PROPERTY_VALUES.meta).sectionId||'nosection')===sec.id); if(!rows.length)return ''; return '<h3 class="course-ref-section-title">'+esc(sec.title)+'</h3>'+rows.map(m=>{let kind=materialKind(m), mm=j(m.PROPERTY_VALUES.meta), done=isDone(m.ID,kind), locked=!done&&!canOpenCourseMaterial(m), req=mm.required===true||mm.required==='Y'; return '<div class="course-ref-row '+(done?'done':'')+' '+(locked?'locked':'')+'" data-umat="'+m.ID+'" title="'+(locked?'Сначала завершите предыдущий обязательный материал':'Открыть материал')+'"><div class="course-ref-icon">'+ico(kind)+'</div><div class="course-ref-body"><div><span class="pill '+(kind==='test'?'red':'mint')+'">'+typeLabel(kind)+'</span><span class="pill '+(req?'red':'gray')+'">'+(req?'Обязательный':'Необязательный')+'</span></div><b>'+esc(m.NAME)+'</b></div><span class="pill '+(done?'green':locked?'gray':'yellow')+'">'+(done?'Пройден':locked?'Закрыто':'Не начато')+'</span></div>'}).join('')}).join('')+'</div>'}
function renderTestsUser(cid){setTimeout(()=>{$$('[data-umat]').forEach(b=>b.onclick=()=>openUserMaterial(findItem(b.dataset.umat))); $$('[data-take-test]').forEach(f=>f.onsubmit=takeTestSubmit); $$('[data-start-user-test]').forEach(b=>b.onclick=()=>{let t=findItem(b.dataset.startUserTest); $('#uMaterialBody').innerHTML=renderTakeTest(t); $$('[data-take-test]').forEach(f=>f.onsubmit=takeTestSubmit)})},0); return ''}
async function takeTestSubmit(e){e.preventDefault(); let tid=e.currentTarget.dataset.takeTest, t=findItem(tid), meta=testDefaults(j(t.PROPERTY_VALUES.meta)), qs=meta.questions||[]; if(meta.timeLimit){let elapsed=(Date.now()-Number(e.currentTarget.dataset.testStart||Date.now()))/60000; if(elapsed>meta.timeLimit){alert('Время теста истекло'); return}} let good=0; qs.forEach((q,qi)=>{let selected=[...e.currentTarget.querySelectorAll('[name="t'+tid+'q'+qi+'"]:checked')].map(x=>+x.value).sort().join(','); let correct=(q.correct||[]).slice().sort().join(','); if(selected===correct)good++}); let score=qs.length?Math.round(good/qs.length*100):0, passed=score>=meta.passScore; await add(E.attempts,'Попытка теста',{courseId:String(state.courseId),testId:String(tid),userId:effectiveUserId(),score:String(score),passed:passed?'Y':'N',createdAt:now()}); let place=e.currentTarget.querySelector('.test-result-place'); place.className='test-result-place test-result '+(passed?'ok':'bad'); place.innerHTML='<b>Результат: '+score+'% ('+good+' из '+qs.length+')</b><br>Порог прохождения: '+meta.passScore+'%.'+(passed?'<div class="inline-actions"><button class="primary" data-test-finish="'+tid+'">Завершить</button></div>':'<div class="inline-actions"><button class="primary" data-test-retry="'+tid+'">Попробовать снова</button><button data-test-close>Закрыть</button></div>'); if(passed)await complete(tid,'test'); $$('[data-test-finish]').forEach(b=>b.onclick=()=>openUserCourse(findItem(state.courseId))); $$('[data-test-retry]').forEach(b=>b.onclick=()=>openUserMaterial(findItem(b.dataset.testRetry))); $$('[data-test-close]').forEach(b=>b.onclick=()=>openUserCourse(findItem(state.courseId))); renderProfile()}
function canOpenCourseMaterial(m){let cid=m.PROPERTY_VALUES.parentId; if(!cid)return true; let course=findItem(cid); if(!course)return true; let cm=j(course.PROPERTY_VALUES.meta); if(!cm.sequential)return true; let list=courseMaterials(cid); let idx=list.findIndex(x=>String(x.ID)===String(m.ID)); if(idx<=0)return true; return list.slice(0,idx).filter(x=>{let mx=j(x.PROPERTY_VALUES.meta); return mx.required===true||mx.required==='Y'}).every(x=>isDone(x.ID,materialKind(x)))}
function renderTakeTest(t){let meta=testDefaults(j(t.PROPERTY_VALUES.meta)), raw=meta.questions||[], attempts=testAttemptsUsed(t.ID), left=Math.max(0,meta.attemptsLimit-attempts); if(left<=0)return '<div class="test-intro-card"><h3>'+esc(t.NAME)+'</h3><p class="muted">Попытки закончились</p></div>'; let questions=meta.shuffleQuestions?shuffleCopy(raw).map(x=>({q:x.v,orig:x.i})):raw.map((q,i)=>({q,orig:i})); return '<form class="take-test-card" data-take-test="'+t.ID+'" data-test-start="'+Date.now()+'"><h3>'+esc(t.NAME)+'</h3><div class="test-meta-grid"><span>Порог: '+meta.passScore+'%</span><span>Попыток осталось: '+left+'</span><span>Время: '+(meta.timeLimit?meta.timeLimit+' мин':'без ограничения')+'</span></div>'+questions.map((row,qi)=>{let q=row.q, answers=(q.answers||[]).map((a,ai)=>({a,ai})); if(meta.shuffleAnswers)answers=shuffleCopy(q.answers||[]).map(x=>({a:x.v,ai:x.i})); return '<div class="test-question"><b>'+(qi+1)+'. '+esc(q.text)+'</b>'+answers.map(x=>'<label class="answer"><input type="'+(q.type==='multiple'?'checkbox':'radio')+'" name="t'+t.ID+'q'+row.orig+'" value="'+x.ai+'">'+esc(x.a)+'</label>').join('')+'</div>'}).join('')+'<button class="primary">Ответить</button><div class="test-result-place"></div></form>'}
function renderUserTestIntro(t){let meta=testDefaults(j(t.PROPERTY_VALUES.meta)), attempts=testAttemptsUsed(t.ID), left=Math.max(0,meta.attemptsLimit-attempts), best=state.attempts.filter(a=>String(a.PROPERTY_VALUES?.testId)===String(t.ID)&&String(a.PROPERTY_VALUES?.userId)===currentUserId()&&String(a.PROPERTY_VALUES?.passed)==='Y').map(a=>+a.PROPERTY_VALUES.score).filter(n=>!isNaN(n)).sort((a,b)=>b-a)[0]; return '<div class="test-intro-card"><h2>'+esc(t.NAME)+'</h2><div class="test-info-grid"><span title="Ограничение времени">⏱ '+(meta.timeLimit?meta.timeLimit+' мин':'Без ограничения')+'</span><span title="Доступные попытки">↻ '+left+' попыток</span><span title="Порог прохождения">'+meta.passScore+'%</span><span title="Последний успешный результат">★ '+(best==null?'—':best+'%')+'</span><span title="Очки за успешное прохождение">'+meta.points+' очков</span><span title="Сертификат">'+(meta.certificate?'Сертификат выдается':'Сертификат не выдается')+'</span></div><button class="primary" data-start-user-test="'+t.ID+'" '+(left<=0?'disabled':'')+'>Приступить</button></div>'}
function openUserMaterial(m){if(!m)return; let fromView=state.uview||'learn', cid=m.PROPERTY_VALUES.parentId, kind=materialKind(m); $("#userMaterialView")?.classList.toggle("is-excalidraw-article",kind==="article"); if(cid){let course=findItem(cid), cm=course?j(course.PROPERTY_VALUES.meta):{}; if(cm.sequential&&!canOpenCourseMaterial(m)){alert('Сначала завершите предыдущий обязательный материал.'); return;} state.courseId=cid;} state.materialBackView=fromView; showUserView('learn'); $('#userCourseListView')?.classList.add('hidden'); $('#userCourseView')?.classList.add('hidden'); $('#userMaterialView')?.classList.remove('hidden'); $('#userMaterialView').dataset.id=m.ID; $('#uMaterialTitle').textContent=m.NAME; $('#uMaterialStatus').textContent=typeLabel(kind); $('#uPrevMaterial').classList.add('hidden'); $('#uNextMaterial').classList.add('hidden'); $('#uMarkMaterialDone').textContent='Завершить'; if(kind==='test'){$('#uMarkMaterialDone').classList.add('hidden'); $('#uMaterialBody').innerHTML=renderUserTestIntro(m); setTimeout(()=>{$$('[data-start-user-test]').forEach(b=>b.onclick=()=>{$('#uMaterialBody').innerHTML=renderTakeTest(m); $$('[data-take-test]').forEach(f=>f.onsubmit=takeTestSubmit)})},0)}else if(kind==='article'){$('#uMarkMaterialDone').classList.add('hidden'); if(window.RTMV45)window.RTMV45.renderUserArticle(m); else $('#uMaterialBody').innerHTML='<article class="reader-page user-article-page">'+materialReaderHtml(m)+'</article>'}else{$('#uMarkMaterialDone').classList.remove('hidden'); $('#uMaterialBody').innerHTML='<article class="reader-page user-article-page">'+materialReaderHtml(m)+'</article>'} addEvent('Открытие',m).catch(e=>console.warn(e))}
function showUserCourses(){document.body.classList.remove('is-reading-article'); $('#userCourseListView').classList.remove('hidden'); $$('#userCourseView,#userMaterialView').forEach(v=>v.classList.add('hidden')); renderUserCourses();}
async function complete(id,type){let uid=effectiveUserId(), it=findItem(id), kind=type||materialKind(it), exists=isDone(id,kind); if(!exists){let props={targetId:String(id),targetType:kind,userId:uid,status:'completed',completedAt:now()}; let pid=await add(E.progress,'progress',props); state.progress=state.progress.filter(p=>String(p.ID)!==String(pid)); state.progress.unshift({ID:String(pid),NAME:'progress',PROPERTY_VALUES:props,DATE_CREATE:now()}); await addEvent('Завершение',it); await persistNow(); toast('Завершено')} renderProfile(); renderDashboard(); renderUserCourses()}
async function finishCurrentArticle(){let id=$('#userMaterialView')?.dataset.id,item=findItem(id);if(!item)return;await complete(id,materialKind(item));document.body.classList.remove('is-reading-article');if(item.PROPERTY_VALUES.parentId)openUserCourse(findItem(item.PROPERTY_VALUES.parentId));else backFromUserMaterial()}
window.finishCurrentArticle=finishCurrentArticle;
function assignedCourses(){let uid=effectiveUserId(); let ids=state.assigns.filter(a=>String(a.PROPERTY_VALUES.userId)===String(uid)).map(a=>String(a.PROPERTY_VALUES.targetId)); let pub=activeRows(state.items).filter(i=>i.PROPERTY_VALUES.type==='course'&&i.PROPERTY_VALUES.status==='published'); return ids.length?pub.filter(c=>ids.includes(String(c.ID))):pub}
function courseMaterials(cid){return activeRows(state.items).filter(i=>String(i.PROPERTY_VALUES.parentId)===String(cid)).sort((a,b)=>(j(a.PROPERTY_VALUES.meta).order||0)-(j(b.PROPERTY_VALUES.meta).order||0))}
function progressTypeAliases(id,type){let it=findItem(id), aliases=new Set([String(type||''),String(it?.PROPERTY_VALUES?.type||''),String(materialKind(it)||'')].filter(Boolean)); return aliases}
function currentProgressUserIds(){return new Set([currentUserId(),effectiveUserId()].filter(Boolean).map(String))}
function isDone(id,type){let aliases=progressTypeAliases(id,type), users=currentProgressUserIds(); return state.progress.some(p=>String(p.PROPERTY_VALUES.targetId)===String(id)&&aliases.has(String(p.PROPERTY_VALUES.targetType||''))&&users.has(String(p.PROPERTY_VALUES.userId))&&p.PROPERTY_VALUES.status==='completed')}
function courseInProcess(cid){return courseMaterials(cid).some(m=>isDone(m.ID,materialKind(m)))}
function isOverdue(cid){let a=assignment(cid), d=a?.PROPERTY_VALUES?.dueAt; return d&&!isDone(cid,'course')&&new Date(d).getTime()<Date.now()}
function assignment(cid){let users=currentProgressUserIds(); return state.assigns.find(a=>String(a.PROPERTY_VALUES.targetId)===String(cid)&&users.has(String(a.PROPERTY_VALUES.userId)))}
function assignText(cid){let a=assignment(cid); if(!a)return ''; return `<p class="muted">\u041d\u0430\u0437\u043d\u0430\u0447\u0435\u043d\u043e: ${fmt(a.DATE_CREATE)} ${a.PROPERTY_VALUES.dueAt?' \u00b7 \u0414\u0435\u0434\u043b\u0430\u0439\u043d: '+fmt(a.PROPERTY_VALUES.dueAt):''}</p>`}
function createByType(type){ if(type==='folder') return folderModal(); if(type==='upload') return fileModal('upload'); if(type==='bitrix') return fileModal('bitrix'); if(type==='course') return createMaterial('course','\u041d\u043e\u0432\u044b\u0439 \u043a\u0443\u0440\u0441'); if(type==='article') return createMaterial('article','\u041d\u043e\u0432\u0430\u044f \u0441\u0442\u0430\u0442\u044c\u044f'); if(type==='test') return createMaterial('test','\u041d\u043e\u0432\u044b\u0439 \u0442\u0435\u0441\u0442');}
function folderModal(){modal(`<h2>\u041d\u043e\u0432\u0430\u044f \u043f\u0430\u043f\u043a\u0430</h2><input id="folderName" placeholder="\u041d\u0430\u0437\u0432\u0430\u043d\u0438\u0435 \u043f\u0430\u043f\u043a\u0438"><div class="inline-actions"><button onclick="window.closeModal()">\u041e\u0442\u043c\u0435\u043d\u0430</button><button class="primary" id="folderCreate">\u0421\u043e\u0437\u0434\u0430\u0442\u044c</button></div>`); $('#folderCreate').onclick=async()=>{let n=$('#folderName').value.trim(); if(!n)return; closeModal(); await createMaterial('folder',n)}}
function fileModal(kind){modal(`<h2>${kind==='upload'?'\u0417\u0430\u0433\u0440\u0443\u0437\u0438\u0442\u044c \u0444\u0430\u0439\u043b':'\u0424\u0430\u0439\u043b \u0438\u0437 Bitrix'}</h2><p class="muted">\u0412 \u044d\u0442\u043e\u0439 \u0432\u0435\u0440\u0441\u0438\u0438 \u0444\u0430\u0439\u043b \u0441\u043e\u0445\u0440\u0430\u043d\u044f\u0435\u0442\u0441\u044f \u043a\u0430\u043a \u043a\u0430\u0440\u0442\u043e\u0447\u043a\u0430 \u043c\u0430\u0442\u0435\u0440\u0438\u0430\u043b\u0430. \u0420\u0435\u0430\u043b\u044c\u043d\u043e\u0435 \u0441\u043e\u0445\u0440\u0430\u043d\u0435\u043d\u0438\u0435 \u0444\u0430\u0439\u043b\u0430 \u0432 \u0414\u0438\u0441\u043a \u0411\u0438\u0442\u0440\u0438\u043a\u044124 \u0432\u043a\u043b\u044e\u0447\u0438\u043c \u043f\u043e\u0441\u043b\u0435 \u0434\u043e\u0431\u0430\u0432\u043b\u0435\u043d\u0438\u044f \u043f\u0440\u0430\u0432\u0430 disk.</p><input id="fileTitle" placeholder="\u041d\u0430\u0437\u0432\u0430\u043d\u0438\u0435 \u0444\u0430\u0439\u043b\u0430"><input type="file" id="fileInput"><div class="inline-actions"><button onclick="window.closeModal()">\u041e\u0442\u043c\u0435\u043d\u0430</button><button class="primary" id="saveFile">\u0421\u043e\u0437\u0434\u0430\u0442\u044c</button></div>`); $('#saveFile').onclick=async()=>{let f=$('#fileInput').files[0]; let n=$('#fileTitle').value.trim()||f?.name||'\u0424\u0430\u0439\u043b'; closeModal(); await createMaterial('file',n,{source:kind,fileName:f?.name||n})}}
function itemActions(id){let it=findItem(id); modal(`<h2>${esc(it.NAME)}</h2><div class="mini-list"><button id="renItem">\u041f\u0435\u0440\u0435\u0438\u043c\u0435\u043d\u043e\u0432\u0430\u0442\u044c</button><button id="copyItem">\u041a\u043e\u043f\u0438\u0440\u043e\u0432\u0430\u0442\u044c</button><button id="moveItem">\u041f\u0435\u0440\u0435\u043c\u0435\u0441\u0442\u0438\u0442\u044c</button><button class="danger" id="deleteItem">\u0423\u0434\u0430\u043b\u0438\u0442\u044c</button></div>`); $('#renItem').onclick=()=>renameItem(id); $('#copyItem').onclick=async()=>{closeModal(); await add(E.items,'\u041a\u043e\u043f\u0438\u044f \u2014 '+it.NAME,{...it.PROPERTY_VALUES,updatedAt:now()}); await loadAll();}; $('#moveItem').onclick=()=>moveModal(id); $('#deleteItem').onclick=async()=>{if(confirm('Удалить в корзину?')){closeModal(); await softDeleteItem(id);}}}
function projectActions(id){let p=state.projects.find(x=>String(x.ID)===String(id)); modal(`<h2>${esc(p.NAME)}</h2><div class="mini-list"><button id="renProject">\u041f\u0435\u0440\u0435\u0438\u043c\u0435\u043d\u043e\u0432\u0430\u0442\u044c</button><button class="danger" id="delProject">\u0423\u0434\u0430\u043b\u0438\u0442\u044c</button></div>`); $('#renProject').onclick=async()=>{let n=prompt('\u041d\u043e\u0432\u043e\u0435 \u043d\u0430\u0437\u0432\u0430\u043d\u0438\u0435',p.NAME); if(n){await upd(E.projects,id,n,p.PROPERTY_VALUES); closeModal(); await loadAll();}}; $('#delProject').onclick=async()=>{if(confirm('Переместить проект и его материалы в корзину?')){closeModal(); await softDeleteProject(id);}}}
function renameItem(id){let it=findItem(id), n=prompt('\u041d\u043e\u0432\u043e\u0435 \u043d\u0430\u0437\u0432\u0430\u043d\u0438\u0435',it.NAME); if(n){upd(E.items,id,n,{...it.PROPERTY_VALUES,updatedAt:now()}).then(loadAll); closeModal();}}
function moveModal(id){modal(`<h2>\u041f\u0435\u0440\u0435\u043c\u0435\u0441\u0442\u0438\u0442\u044c</h2><p class="muted">\u0412\u044b\u0431\u0435\u0440\u0438\u0442\u0435 \u043f\u0440\u043e\u0435\u043a\u0442</p><select id="moveProject">${state.projects.map(p=>`<option value="${p.ID}">${esc(p.NAME)}</option>`)}</select><div class="inline-actions"><button onclick="window.closeModal()">\u041e\u0442\u043c\u0435\u043d\u0430</button><button class="primary" id="moveSave">\u041f\u0435\u0440\u0435\u043c\u0435\u0441\u0442\u0438\u0442\u044c</button></div>`); $('#moveSave').onclick=async()=>{let it=findItem(id); await upd(E.items,id,it.NAME,{...it.PROPERTY_VALUES,projectId:$('#moveProject').value,parentId:'root',updatedAt:now()}); closeModal(); await loadAll();}}
