function bindLate(){ $('#backFromCourseEditor').onclick=backFromEditor; $('#backFromArticleEditor').onclick=backFromEditor; $('#backFromTestEditor').onclick=backFromEditor; $('#addToCourseBtn').onclick=courseAddModal; $('#coursePublishBtn').onclick=publishCourse; $('#deleteCourseDraft').onclick=async()=>{if(confirm('Удалить курс в корзину?')){let id=state.courseId; showMaterialsList(); await softDeleteItem(id);}}; $('#courseNameInput').oninput=()=>debounceSave('course',saveCourseSettings); $('#courseDescInput').oninput=()=>debounceSave('course',saveCourseSettings); $('#coursePointsInput').oninput=()=>debounceSave('course',saveCourseSettings); $('#courseCertificateInput').onchange=saveCourseSettings; $('#courseSequentialInput').onchange=saveCourseSettings; $('#showCourseLinkBtn').onclick=()=>{$('#courseLinkBox').classList.toggle('hidden'); $('#courseLinkBox').textContent=location.href.split('?')[0]+'?course='+state.courseId}; $('#assignCourseBtn').onclick=assignCourse; $$('.editor-tab[data-course-tab-editor]').forEach(b=>b.onclick=()=>{switchTab('course',b.dataset.courseTabEditor)}); $('#backFromArticleEditor').onclick=backFromEditor; $('#articleContentEditable').oninput=()=>debounceSave('articlePage',saveCurrentArticlePage,900); $('#articleContentEditable').onmouseup=saveRichSelection; $('#articleContentEditable').onkeyup=saveRichSelection; $('#addArticlePageBtn').onclick=addArticlePage; $('#articlePublishBtn').onclick=publishArticle; $('#articleNameInput').oninput=()=>debounceSave('articleSettings',saveArticleSettings); $('#articleDescInput').oninput=()=>debounceSave('articleSettings',saveArticleSettings); $('#articlePointsInput').oninput=()=>debounceSave('articleSettings',saveArticleSettings); $('#assignArticleBtn').onclick=assignArticle; $$('.editor-tab[data-article-editor-tab]').forEach(b=>b.onclick=()=>switchTab('article',b.dataset.articleEditorTab)); $$('.format-toolbar button[data-cmd]').forEach(b=>b.onclick=e=>{e.preventDefault(); runRichCommand(b.dataset.cmd)}); $('#formatBlock').onchange=()=>runRichCommand('formatBlock',$('#formatBlock').value); $('#fontName').onchange=()=>runRichCommand('fontName',$('#fontName').value); $('#fontColor').oninput=()=>runRichCommand('foreColor',$('#fontColor').value); $('#insertLinkBtn').onclick=()=>insertCustomLink(); $('#articleContentEditable').onpaste=handleRichPaste; $('#addQuestionBtn').onclick=addQuestion; $('#publishTestBtn').onclick=publishTest; $('#backFromTestEditor').onclick=showMaterialsList;}
setTimeout(bindLate,1000);
function courseAddModal(){modal(`<h2>Добавить в курс</h2><button class="modal-close" onclick="window.closeModal()">&times;</button><div class="add-material-grid course-add-grid"><div class="add-tile" id="addCourseMaterial">${svgIcon('article')}<div><h3>Материал</h3><p class="muted">Статья, тест, файл или курс</p></div></div><div class="add-tile" id="addCourseSection">${svgIcon('folder')}<div><h3>Секция</h3><p class="muted">Группа материалов внутри курса</p></div></div></div>`); $('#addCourseMaterial').onclick=()=>{closeModal(); addMaterialModalForCourse()}; $('#addCourseSection').onclick=()=>{let n=prompt('Название секции'); if(n)addSection(n); closeModal();}}
async function addSection(n){let c=findItem(state.courseId), meta=j(c.PROPERTY_VALUES.meta); meta.sections=meta.sections||[{id:'nosection',title:'\u0411\u0435\u0437 \u0441\u0435\u043a\u0446\u0438\u0438',order:0}]; meta.sections.push({id:uid(),title:n,order:Date.now()}); await saveItemMeta(state.courseId,meta); renderCourseEditor();}
async function renameSection(id){let c=findItem(state.courseId), meta=j(c.PROPERTY_VALUES.meta), s=meta.sections.find(x=>x.id===id), n=prompt('\u041d\u0430\u0437\u0432\u0430\u043d\u0438\u0435 \u0441\u0435\u043a\u0446\u0438\u0438',s.title); if(n){s.title=n; await saveItemMeta(c.ID,meta); renderCourseEditor();}}
async function moveSection(id,d){let c=findItem(state.courseId), meta=j(c.PROPERTY_VALUES.meta); meta.sections=meta.sections&&meta.sections.length?meta.sections:[{id:'nosection',title:'Без секции',order:0}]; let arr=meta.sections.sort((a,b)=>(a.order||0)-(b.order||0)); arr.forEach((x,i)=>x.order=(i+1)*100); let i=arr.findIndex(x=>x.id===id), to=i+d; if(i<0||to<0||to>=arr.length)return; let moved=arr.splice(i,1)[0]; arr.splice(to,0,moved); arr.forEach((x,idx)=>x.order=(idx+1)*100); meta.sections=arr; await saveItemMeta(c.ID,meta); renderCourseEditor(); toast('Порядок секций обновлен')}
async function moveMaterial(id,d){let it=findItem(id); if(!it)return; let meta=j(it.PROPERTY_VALUES.meta), section=meta.sectionId||'nosection'; let siblings=activeRows(state.items).filter(x=>String(x.PROPERTY_VALUES.parentId)===String(it.PROPERTY_VALUES.parentId)&&(j(x.PROPERTY_VALUES.meta).sectionId||'nosection')===section).sort((a,b)=>(j(a.PROPERTY_VALUES.meta).order||0)-(j(b.PROPERTY_VALUES.meta).order||0)); siblings.forEach((x,i)=>{let m=j(x.PROPERTY_VALUES.meta); if(!m.order){m.order=(i+1)*100; x.PROPERTY_VALUES.meta=json(m)}}); let idx=siblings.findIndex(x=>String(x.ID)===String(id)), to=idx+d; if(idx<0||to<0||to>=siblings.length)return; let moved=siblings.splice(idx,1)[0]; siblings.splice(to,0,moved); for(let i=0;i<siblings.length;i++){let m=j(siblings[i].PROPERTY_VALUES.meta); m.order=(i+1)*100; await saveItemMeta(siblings[i].ID,m)} renderCourseEditor(); toast('Порядок материалов обновлен')}
async function saveCourseSettings(){let c=findItem(state.courseId); if(!c)return; let meta=j(c.PROPERTY_VALUES.meta); meta.points=$('#coursePointsInput').value; meta.certificate=$('#courseCertificateInput').checked; meta.sequential=$('#courseSequentialInput').checked; let name=$('#courseNameInput').value||c.NAME, props={...c.PROPERTY_VALUES,content:$('#courseDescInput').value,meta:json(meta),updatedAt:now()}; updateLocalItem(c.ID,name,props); await upd(E.items,c.ID,name,props);}
async function publishCourse(){await saveCourseSettings(); let c=findItem(state.courseId); await upd(E.items,c.ID,$('#courseNameInput').value||c.NAME,{...c.PROPERTY_VALUES,status:'published',updatedAt:now()}); await addEvent('\u041f\u0443\u0431\u043b\u0438\u043a\u0430\u0446\u0438\u044f',c); await loadAll(true); openCourseEditor(state.courseId); toast('Курс опубликован');}

let savedRichRange=null;
function saveRichSelection(){let sel=window.getSelection(); if(sel&&sel.rangeCount&&document.activeElement?.classList?.contains('rich-editor'))savedRichRange=sel.getRangeAt(0).cloneRange()}
function restoreRichSelection(){if(!savedRichRange)return; let sel=window.getSelection(); sel.removeAllRanges(); sel.addRange(savedRichRange)}
function runRichCommand(cmd,value=null){let ed=currentRichEditor(); if(ed)ed.focus(); restoreRichSelection(); if(cmd==='formatBlock'&&value)value='<'+value.replace(/[<>]/g,'')+'>'; document.execCommand(cmd,false,value); saveRichSelection(); if(ed)ed.dispatchEvent(new Event('input',{bubbles:true}))}

function normalizeUrl(url){url=String(url||'').trim(); if(!url)return ''; return /^https?:\/\//i.test(url)?url:'https://'+url.replace(/^\/+/,'')}
function isPlainUrl(text){return /^(https?:\/\/|www\.)\S+$/i.test(String(text||'').trim())}
function insertLinkHtml(text,url){url=normalizeUrl(url); if(!url)return; document.execCommand('insertHTML',false,'<a href="'+esc(url)+'" target="_blank" rel="noopener">'+esc(text||url)+'</a>')}
function insertCustomLink(){restoreRichSelection(); let selected=String(window.getSelection()?.toString()||''); let url=prompt('Вставьте ссылку','https://'); if(!url)return; insertLinkHtml(selected||normalizeUrl(url),url)}
function handleRichPaste(e){let text=(e.clipboardData||window.clipboardData)?.getData('text')||''; if(!isPlainUrl(text))return; e.preventDefault(); insertLinkHtml(text.trim(),text.trim())}
function renderArticlePages(){if(window.RTMV40)return window.RTMV40.renderArticlePages(); let a=findItem(state.articleId); if(!a)return; let meta=j(a.PROPERTY_VALUES.meta); meta.pages=meta.pages&&meta.pages.length?meta.pages:[{title:a.NAME,html:a.PROPERTY_VALUES.content||'<h1>'+esc(a.NAME)+'</h1><p><br></p>'}]; if(state.articlePage>=meta.pages.length)state.articlePage=0; $('#articlePagesList').innerHTML=meta.pages.map((p,i)=>'<div class="page-row '+(i===state.articlePage?'active':'')+'" data-article-page="'+i+'">'+ico('article')+'<span>'+esc(p.title||('Страница '+(i+1)))+'</span></div>').join(''); $('#articleContentEditable').innerHTML=meta.pages[state.articlePage]?.html||'<h1>Новая страница</h1><p><br></p>'; $$('[data-article-page]').forEach(b=>b.onclick=async()=>{await saveCurrentArticlePage(); state.articlePage=Number(b.dataset.articlePage); renderArticlePages()})}
async function addArticlePage(){let a=findItem(state.articleId); if(!a)return; await saveCurrentArticlePage(); a=findItem(state.articleId); let meta=j(a.PROPERTY_VALUES.meta); meta.pages=meta.pages&&meta.pages.length?meta.pages:[]; meta.pages.push({id:'page_'+uid(),title:'Страница '+(meta.pages.length+1),html:'<h1>Новая страница</h1><p><br></p>',canvasRef:null}); let props={...a.PROPERTY_VALUES,meta:json(meta),content:meta.pages.map(p=>p.html).join('<hr>'),updatedAt:now()}; updateLocalItem(a.ID,a.NAME,props); await upd(E.items,a.ID,a.NAME,props); state.articlePage=meta.pages.length-1; renderArticlePages(); toast('Страница добавлена')}
function initFontSizes(){let sel=$('#fontSizePt'); if(!sel||sel.dataset.ready)return; sel.innerHTML=Array.from({length:35},(_,i)=>'<option value="'+(i+1)+'" '+((i+1)===12?'selected':'')+'>'+(i+1)+' пт</option>').join(''); sel.dataset.ready='1'}
function applyFontSize(pt){let ed=currentRichEditor(); if(ed)ed.focus(); restoreRichSelection(); document.execCommand('fontSize',false,7); document.querySelectorAll('font[size="7"]').forEach(f=>{f.removeAttribute('size'); f.style.fontSize=pt+'pt'}); if(ed)ed.dispatchEvent(new Event('input',{bubbles:true}))}
function articlePageTitle(html,fallback){let box=document.createElement('div'); box.innerHTML=html||''; box.querySelectorAll('.rtm-block-tools,.v38-image-resize,.v39-media-error-panel,script,style').forEach(x=>x.remove()); let heading=box.querySelector('h1,h2,h3'); let text=String(heading?.textContent||box.textContent||'').replace(/\s+/g,' ').trim(); return text.slice(0,40)||fallback||'Новая страница'}
async function saveCurrentArticlePage(){if(window.RTMV40)return window.RTMV40.saveCurrentArticlePage(); let a=findItem(state.articleId); if(!a)return; let meta=j(a.PROPERTY_VALUES.meta); meta.pages=meta.pages||[{title:a.NAME,html:''}]; let html=$('#articleContentEditable').innerHTML, previous=meta.pages[state.articlePage]?.title; meta.pages[state.articlePage]={title:articlePageTitle(html,previous),html}; let name=$('#articleNameInput').value||a.NAME, props={...a.PROPERTY_VALUES,content:meta.pages.map(p=>p.html).join('<hr>'),meta:json(meta),updatedAt:now()}; updateLocalItem(a.ID,name,props); await upd(E.items,a.ID,name,props); $('#articleSaveInfo').textContent='Все изменения сохранены в '+new Date().toLocaleTimeString();}
async function saveArticleSettings(){let a=findItem(state.articleId); if(!a)return; let meta=j(a.PROPERTY_VALUES.meta); meta.description=$('#articleDescInput').value; meta.points=$('#articlePointsInput').value; let name=$('#articleNameInput').value||a.NAME, props={...a.PROPERTY_VALUES,meta:json(meta),updatedAt:now()}; updateLocalItem(a.ID,name,props); await upd(E.items,a.ID,name,props);}
async function publishArticle(){await saveCurrentArticlePage();let a=findItem(state.articleId);await upd(E.items,a.ID,$('#articleNameInput').value||a.NAME,{...a.PROPERTY_VALUES,status:'published',updatedAt:now()});await addEvent('Публикация',a);await loadAll(true);openArticleEditor(state.articleId);toast('Статья опубликована')}
async function addQuestion(){let t=findItem(state.testId); if(!t)return alert('Тест не выбран. Откройте тест заново.'); await saveTestSettings().catch(()=>{}); let meta=j(findItem(state.testId).PROPERTY_VALUES.meta); meta.questions=meta.questions||[]; meta.questions.push({id:uid(),type:'single',text:'Новый вопрос',answers:['Ответ 1','Ответ 2'],correct:[0]}); await saveItemMeta(t.ID,meta); renderTestEditor(); let addBtn=$('#addQuestionBtn'); if(addBtn)addBtn.onclick=addQuestion; toast('Вопрос добавлен')}
async function publishTest(){await saveTestFromEditor(); let t=findItem(state.testId); await upd(E.items,t.ID,t.NAME,{...t.PROPERTY_VALUES,status:'published',updatedAt:now()}); await addEvent('\u041f\u0443\u0431\u043b\u0438\u043a\u0430\u0446\u0438\u044f',t); await loadAll(true); openTestEditor(state.testId); toast('Тест опубликован');}
async function saveItemMeta(id,meta){let it=findItem(id); if(!it)return; let props={...it.PROPERTY_VALUES,meta:json(meta),updatedAt:now()}; updateLocalItem(id,it.NAME,props); await upd(E.items,id,it.NAME,props);}
function modal(html){$('#modalBox').innerHTML=html; $('#modalBackdrop').classList.remove('hidden')} function closeModal(){$('#modalBackdrop').classList.add('hidden')} window.closeModal=closeModal; $('#modalBackdrop').addEventListener('click',e=>{if(e.target.id==='modalBackdrop')closeModal()});
function isDeletedRow(x){return x?.PROPERTY_VALUES?.deleted==='Y'}
function activeRows(rows){return (rows||[]).filter(x=>!isDeletedRow(x))}
function deletedRows(rows){return (rows||[]).filter(isDeletedRow)}
function findItem(id){return state.items.find(i=>String(i.ID)===String(id))} function projectName(id){if(String(id)==='trash')return 'Корзина'; return state.projects.find(p=>String(p.ID)===String(id))?.NAME||'Root'} function projectCode(id){let n=projectName(id).toLowerCase(); if(n.includes('\u043c\u043e\u043d\u0442\u0430\u0436'))return'montage'; if(n.includes('\u043c\u0435\u043d\u0435\u0434\u0436'))return'manager'; return'root'} function spaceLabel(s){return {root:'Root',manager:'\u041c\u0435\u043d\u0435\u0434\u0436\u0435\u0440 \u043f\u0440\u043e\u0435\u043a\u0442\u043e\u0432',montage:'\u041c\u043e\u043d\u0442\u0430\u0436\u043d\u044b\u0439 \u043e\u0442\u0434\u0435\u043b',base:'\u0411\u0430\u0437\u0430'}[s]||s||'Root'} function typeLabel(t){return {folder:'\u041f\u0430\u043f\u043a\u0430',article:'\u0421\u0442\u0430\u0442\u044c\u044f',test:'\u0422\u0435\u0441\u0442',course:'\u041a\u0443\u0440\u0441',file:'\u0424\u0430\u0439\u043b'}[t]||t} function statusLabel(s){return s==='published'?'\u041e\u043f\u0443\u0431\u043b\u0438\u043a\u043e\u0432\u0430\u043d\u043e':'\u0427\u0435\u0440\u043d\u043e\u0432\u0438\u043a'} function esc(s){return String(s??'').replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#039;'}[m]))} function strip(s){return String(s||'').replace(/<[^>]+>/g,' ')} function j(s){try{return JSON.parse(s||'{}')}catch{return {}}} function json(o){return JSON.stringify(o)} function now(){return new Date().toISOString()} function fmt(s){if(!s)return'\u2014'; let d=new Date(s); return isNaN(d)?s:d.toLocaleString('ru-RU')} function uid(){return 'id_'+Math.random().toString(36).slice(2,10)} function slug(s){return String(s).toLowerCase().replace(/\W+/g,'_').slice(0,12)||uid()} function fullName(u){return `${u?.NAME||''} ${u?.LAST_NAME||''}`.trim()||u?.EMAIL||('ID '+(u?.ID||''))} function cap(s){return s.charAt(0).toUpperCase()+s.slice(1)}
function downloadEventsCsv(){let rows=[['\u0414\u0430\u0442\u0430','\u041f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u0442\u0435\u043b\u044c','\u0421\u043e\u0431\u044b\u0442\u0438\u0435','\u041c\u0430\u0442\u0435\u0440\u0438\u0430\u043b'],...state.events.map(e=>[fmt(e.PROPERTY_VALUES.createdAt),e.PROPERTY_VALUES.userName,e.PROPERTY_VALUES.event,e.PROPERTY_VALUES.targetName])]; let csv=rows.map(r=>r.map(x=>`"${String(x||'').replace(/"/g,'""')}"`).join(';')).join('\n'); let a=document.createElement('a'); a.href=URL.createObjectURL(new Blob([csv],{type:'text/csv;charset=utf-8'})); a.download='rtm_events.csv'; a.click();}
function downloadJsonFile(name,data){let a=document.createElement('a'); a.href=URL.createObjectURL(new Blob([JSON.stringify(data,null,2)],{type:'application/json;charset=utf-8'})); a.download=name; a.click(); setTimeout(()=>URL.revokeObjectURL(a.href),1000)}
function exportAllData(){let data={exportedAt:now(),portal:location.host,entities:{rtm_prj:state.projects,rtm_items:state.items,rtm_assigns:state.assigns,rtm_progress:state.progress,rtm_events:state.events,rtm_attempts:state.attempts,rtm_roles:state.roles},bitrix:{users:state.users,departments:state.departments},snapshot:snapshotData()}; downloadJsonFile('rtm_obuchenie_backup_'+new Date().toISOString().slice(0,10)+'.json',data)}

function itemPathLabel(it){if(!it)return '—'; let project=state.projects.find(p=>String(p.ID)===String(it.PROPERTY_VALUES?.projectId)); if(it.PROPERTY_VALUES?.parentId&&String(it.PROPERTY_VALUES.parentId)!=='root'){let parent=findItem(it.PROPERTY_VALUES.parentId); if(parent?.PROPERTY_VALUES?.type==='course')return (project?.NAME||'Проект')+' / курс: '+parent.NAME; if(parent)return (project?.NAME||'Проект')+' / папка: '+parent.NAME} return project?.NAME||'Корень проекта'}
function trashRows(){let projects=deletedRows(state.projects).map(p=>({kind:'project',id:p.ID,name:p.NAME,type:'Проект',path:p.PROPERTY_VALUES?.deletedPath||'Корень',row:p})); let items=deletedRows(state.items).map(i=>({kind:'item',id:i.ID,name:i.NAME,type:typeLabel(i.PROPERTY_VALUES?.type),path:i.PROPERTY_VALUES?.deletedPath||itemPathLabel(i),row:i})); return projects.concat(items).sort((a,b)=>String(b.row.PROPERTY_VALUES?.deletedAt||'').localeCompare(String(a.row.PROPERTY_VALUES?.deletedAt||'')))}
async function updateProjectRow(p,props){let next={...p.PROPERTY_VALUES,...props,updatedAt:now()}; p.PROPERTY_VALUES=next; await upd(E.projects,p.ID,p.NAME,next)}
async function updateItemRow(it,props){let next={...it.PROPERTY_VALUES,...props,updatedAt:now()}; it.PROPERTY_VALUES=next; await upd(E.items,it.ID,it.NAME,next)}
async function softDeleteItem(id){let it=findItem(id); if(!it)return; await updateItemRow(it,{deleted:'Y',deletedAt:now(),deletedPath:itemPathLabel(it)}); await persistNow(); toast('Перемещено в корзину'); renderAll()}
async function softDeleteProject(id){let p=state.projects.find(x=>String(x.ID)===String(id)); if(!p)return; await updateProjectRow(p,{deleted:'Y',deletedAt:now(),deletedPath:'Корень'}); let children=state.items.filter(i=>String(i.PROPERTY_VALUES?.projectId)===String(id)); for(const it of children)await updateItemRow(it,{deleted:'Y',deletedAt:now(),deletedPath:(p.NAME||'Проект')+' / '+itemPathLabel(it)}); if(String(state.projectId)===String(id))state.projectId=(activeRows(state.projects)[0]||{}).ID||'trash'; await persistNow(); toast('Проект перемещен в корзину'); renderAll()}
async function restoreTrash(kind,id){if(kind==='project'){let p=state.projects.find(x=>String(x.ID)===String(id)); if(p){await updateProjectRow(p,{deleted:'N',deletedAt:'',deletedPath:''}); for(const it of state.items.filter(i=>String(i.PROPERTY_VALUES?.projectId)===String(id)))await updateItemRow(it,{deleted:'N',deletedAt:'',deletedPath:''}); state.projectId=String(id)}} else {let it=findItem(id); if(it)await updateItemRow(it,{deleted:'N',deletedAt:'',deletedPath:''})} await persistNow(); toast('Восстановлено'); renderAll()}
function collectItemTreeIds(seedIds){let ids=new Set((seedIds||[]).map(String)),changed=true;while(changed){changed=false;(state.items||[]).forEach(i=>{if(ids.has(String(i.PROPERTY_VALUES?.parentId))&&!ids.has(String(i.ID))){ids.add(String(i.ID));changed=true}})}return ids}
function deletionPlan(kind,id){let projectIds=new Set(),itemIds=new Set();if(kind==='project'){projectIds.add(String(id));state.items.forEach(i=>{if(String(i.PROPERTY_VALUES?.projectId)===String(id))itemIds.add(String(i.ID))})}else itemIds=collectItemTreeIds([id]);return {projectIds,itemIds:collectItemTreeIds([...itemIds])}}
function relatedRowsForDeletion(itemIds){let match=(row,keys)=>keys.some(k=>itemIds.has(String(row.PROPERTY_VALUES?.[k]||'')));return {assigns:state.assigns.filter(r=>match(r,['targetId'])),progress:state.progress.filter(r=>match(r,['targetId'])),attempts:state.attempts.filter(r=>match(r,['testId','courseId'])),events:state.events.filter(r=>match(r,['targetId']))}}
async function executePermanentDeletion(plan){let errors=[],related=relatedRowsForDeletion(plan.itemIds),remove=async(entity,row)=>{try{await del(entity,row.ID)}catch(e){errors.push(e)}};for(const row of [...new Map(related.assigns.map(r=>[String(r.ID),r])).values()])await remove(E.assigns,row);for(const row of [...new Map(related.progress.map(r=>[String(r.ID),r])).values()])await remove(E.progress,row);for(const row of [...new Map(related.attempts.map(r=>[String(r.ID),r])).values()])await remove(E.attempts,row);for(const row of related.events){let props=Object.assign({},row.PROPERTY_VALUES),suffix=' (материал удалён)';if(!String(props.targetName||'').endsWith(suffix))props.targetName=(props.targetName||'Материал')+suffix;try{await upd(E.events,row.ID,row.NAME,props);row.PROPERTY_VALUES=props}catch(e){errors.push(e)}}for(const row of [...new Map(state.items.filter(i=>plan.itemIds.has(String(i.ID))).map(r=>[String(r.ID),r])).values()])await remove(E.items,row);for(const row of [...new Map(state.projects.filter(p=>plan.projectIds.has(String(p.ID))).map(r=>[String(r.ID),r])).values()])await remove(E.projects,row);state.assigns=state.assigns.filter(r=>!related.assigns.some(x=>String(x.ID)===String(r.ID)));state.progress=state.progress.filter(r=>!related.progress.some(x=>String(x.ID)===String(r.ID)));state.attempts=state.attempts.filter(r=>!related.attempts.some(x=>String(x.ID)===String(r.ID)));state.items=state.items.filter(i=>!plan.itemIds.has(String(i.ID)));state.projects=state.projects.filter(p=>!plan.projectIds.has(String(p.ID)));await persistNow();renderAll();if(errors.length){console.error('Permanent deletion completed with errors',errors);alert('Удаление завершено, но не удалось обработать '+errors.length+' записей. Повторите синхронизацию и очистку.')}return errors}
async function permanentDeleteTrash(kind,id){if(!confirm('Удалить безвозвратно? Назначения, прогресс и попытки будут удалены, история событий сохранится с пометкой.'))return;busy('Удаляю окончательно...');try{await executePermanentDeletion(deletionPlan(kind,id));toast('Удалено окончательно')}finally{idle()}}
async function clearTrash(){let rows=trashRows();if(!rows.length)return;if(!confirm('Очистить корзину безвозвратно? Назначения, прогресс и попытки будут удалены, история событий сохранится с пометкой.'))return;let projectIds=new Set(rows.filter(r=>r.kind==='project').map(r=>String(r.id))),seed=rows.filter(r=>r.kind==='item'&&!projectIds.has(String(r.row.PROPERTY_VALUES?.projectId))).map(r=>String(r.id));state.items.forEach(i=>{if(projectIds.has(String(i.PROPERTY_VALUES?.projectId)))seed.push(String(i.ID))});busy('Очищаю корзину...');try{await executePermanentDeletion({projectIds,itemIds:collectItemTreeIds([...new Set(seed)])});toast('Корзина очищена')}finally{idle()}}
function renderTrashView(){let rows=trashRows(); $('#breadcrumb').innerHTML='Корзина'; $('#backFolderBtn').classList.add('hidden'); $('#createMaterialBtn').classList.add('hidden'); $('#materialSearch').style.display='none'; $('#emptyFolder').classList.toggle('hidden',rows.length>0); $('#materialsTable').innerHTML=rows.map(r=>'<tr><td><b>'+esc(r.name)+'</b><div class="row-sub">Было: '+esc(r.path)+'</div></td><td><span class="pill gray">'+esc(r.type)+'</span></td><td><span class="pill red">В корзине</span></td><td>'+fmt(r.row.DATE_CREATE)+'</td><td>'+fmt(r.row.PROPERTY_VALUES?.deletedAt)+'</td><td>—</td><td>'+esc(r.path)+'</td><td><button data-trash-restore="'+r.kind+':'+r.id+'">Восстановить</button><button class="danger" data-trash-delete="'+r.kind+':'+r.id+'">Удалить</button></td></tr>').join('')||'<tr><td colspan="8">Корзина пуста</td></tr>'; $('#materialsTable').insertAdjacentHTML('beforeend','<tr><td colspan="8"><button class="danger" id="clearTrashBtn">Очистить корзину</button></td></tr>'); $$('[data-trash-restore]').forEach(b=>b.onclick=()=>{let [kind,id]=b.dataset.trashRestore.split(':'); restoreTrash(kind,id)}); $$('[data-trash-delete]').forEach(b=>b.onclick=()=>{let [kind,id]=b.dataset.trashDelete.split(':'); permanentDeleteTrash(kind,id)}); $('#clearTrashBtn').onclick=clearTrash}

function bindDashboardClicks(){let mat=$('#statMaterials')?.closest('.dash-stat'), users=$('#statUsers')?.closest('.dash-stat'); if(mat){mat.dataset.dash='materials'; mat.onclick=()=>switchAdmin('materials')} if(users){users.dataset.dash='users'; users.onclick=()=>switchAdmin('users')} $$('[data-last-material]').forEach(x=>x.onclick=()=>{switchAdmin('materials'); openItem(x.dataset.lastMaterial)}); $$('[data-event-target]').forEach(x=>x.onclick=()=>{let id=x.dataset.eventTarget; if(id){switchAdmin('materials'); openItem(id)}})}
function dbSets(){return [{key:'rtm_prj',title:'Проекты',rows:state.projects},{key:'rtm_items',title:'Материалы',rows:state.items},{key:'rtm_assigns',title:'Назначения',rows:state.assigns},{key:'rtm_progress',title:'Прогресс',rows:state.progress},{key:'rtm_events',title:'События',rows:state.events},{key:'rtm_attempts',title:'Попытки тестов',rows:state.attempts},{key:'rtm_roles',title:'Роли',rows:state.roles},{key:'users',title:'Сотрудники Bitrix24',rows:state.users},{key:'departments',title:'Отделы Bitrix24',rows:state.departments}]}
function renderDatabase(){let wrap=$('#databaseSummary'); if(!wrap)return; let sets=dbSets(); wrap.innerHTML=sets.slice(0,8).map(s=>'<div class="dash-stat"><span>'+esc(s.title)+'</span><b>'+((s.rows||[]).length)+'</b></div>').join(''); let sel=$('#databaseEntitySelect'); if(sel&&!sel.dataset.ready){sel.innerHTML=sets.map(s=>'<option value="'+s.key+'">'+esc(s.title)+' ('+(s.rows||[]).length+')</option>').join(''); sel.dataset.ready='1'; sel.onchange=renderDatabaseTable} else if(sel){let current=sel.value; sel.innerHTML=sets.map(s=>'<option value="'+s.key+'" '+(s.key===current?'selected':'')+'>'+esc(s.title)+' ('+(s.rows||[]).length+')</option>').join('')} $('#dbExportAllBtn')&&($('#dbExportAllBtn').onclick=exportAllData); $('#dbRefreshBtn')&&($('#dbRefreshBtn').onclick=loadAll); renderDatabaseTable()}
function renderDatabaseTable(){let box=$('#databaseTable'), sel=$('#databaseEntitySelect'); if(!box||!sel)return; let set=dbSets().find(s=>s.key===sel.value)||dbSets()[0], rows=set.rows||[]; box.innerHTML='<table class="admin-table"><thead><tr><th>ID</th><th>Название</th><th>Данные</th></tr></thead><tbody>'+(rows.map(r=>'<tr><td>'+esc(r.ID||r.id||'—')+'</td><td>'+esc(r.NAME||fullName(r)||r.EMAIL||'—')+'</td><td><pre class="db-json">'+esc(JSON.stringify(r.PROPERTY_VALUES||r,null,2))+'</pre></td></tr>').join('')||'<tr><td colspan="3">Записей нет</td></tr>')+'</tbody></table>'}



