async function callPage(m,p={}){return new Promise((res,rej)=>BX24.callMethod(m,p,r=>r.error()?rej(new Error(r.error()+': '+r.error_description())):res({data:r.data()||[],more:typeof r.more==='function'?r.more():false}))) }
async function get(entity){try{let out=[], start=0, guard=0; while(guard++<40){let page=await callPage('entity.item.get',{ENTITY:entity,SORT:{ID:'DESC'},start}); out=out.concat(page.data||[]); if(!page.more || (page.data||[]).length===0)break; start+=50;} return out}catch(e){return []}}
async function ensureAll(){await ent(E.projects,'Проекты',[['code','Код'],['description','Описание'],['updatedAt','Изменен'],['deleted','Удалено'],['deletedAt','Дата удаления'],['deletedPath','Откуда удалено']]); await ent(E.items,'Материалы',[['type','Тип'],['status','Статус'],['projectId','Проект'],['parentId','Родитель'],['space','Пространство'],['content','Контент'],['meta','Мета'],['author','Автор'],['authorId','Автор ID'],['updatedAt','Изменен'],['deleted','Удалено'],['deletedAt','Дата удаления'],['deletedPath','Откуда удалено']]); await ent(E.assigns,'Назначения',[['targetId','Материал'],['targetType','Тип'],['userId','Пользователь'],['dueAt','Дедлайн'],['taskId','Задача']]); await ent(E.progress,'Прогресс',[['targetId','Материал'],['targetType','Тип'],['userId','Пользователь'],['status','Статус'],['completedAt','Дата']]); await ent(E.events,'События',[['userId','Пользователь'],['userName','Имя'],['event','Событие'],['targetId','Материал'],['targetName','Название'],['duration','Длительность'],['createdAt','Дата']]); await ent(E.attempts,'Попытки',[['courseId','Курс'],['testId','Тест'],['userId','Пользователь'],['score','Оценка'],['passed','Зачет'],['createdAt','Дата']]); await ent(E.roles,'Роли приложения',[['userId','Пользователь'],['role','Роль'],['updatedAt','Дата']]); await ent(E.canvas,'Сцены Excalidraw',[['articleId','Статья'],['pageId','Страница'],['revision','Ревизия'],['chunkIndex','Номер чанка'],['chunkCount','Всего чанков'],['checksum','Контрольная сумма'],['payload','Данные'],['updatedAt','Дата']]);}

function analyticsRows(){let materials=activeRows(state.items).filter(i=>!['folder','section'].includes(i.PROPERTY_VALUES?.type)), assigns=state.assigns, progress=state.progress; let userRows=state.users.map(u=>{let uid=String(u.ID), assigned=assigns.filter(a=>String(a.PROPERTY_VALUES.userId)===uid).length, done=progress.filter(p=>String(p.PROPERTY_VALUES.userId)===uid&&p.PROPERTY_VALUES.status==='completed').length, inwork=Math.max(0,assigned-done), pct=assigned?Math.round(done/assigned*100):0; return {u,assigned,done,failed:0,inwork,notStarted:Math.max(0,assigned-done-inwork),pct,points:userPoints(uid)}}); let materialRows=materials.map(m=>{let mid=String(m.ID), assigned=assigns.filter(a=>String(a.PROPERTY_VALUES.targetId)===mid||String(a.PROPERTY_VALUES.targetId)===String(m.PROPERTY_VALUES.parentId)).length, done=progress.filter(p=>String(p.PROPERTY_VALUES.targetId)===mid&&p.PROPERTY_VALUES.status==='completed').length, inwork=Math.max(0,assigned-done), pct=assigned?Math.round(done/assigned*100):0; return {m,assigned,done,failed:0,inwork,notStarted:Math.max(0,assigned-done-inwork),pct}}); return {materials,userRows,materialRows}}
function analyticsDeptOptions(){return '<option value="all">Вся компания</option>'+state.departments.map(d=>'<option value="'+d.ID+'">'+esc(d.NAME)+'</option>').join('')}
function analyticsTopbar(searchPlaceholder){return '<div class="analytics-tools"><input id="analyticsSearch" placeholder="'+searchPlaceholder+'"><button id="analyticsExportBtn">⇩ Отчёт</button><button id="analyticsFilterBtn">⌁</button></div><div id="analyticsFilterPanel" class="analytics-filter-panel hidden"><select id="analyticsDept">'+analyticsDeptOptions()+'</select><label>Период</label><input id="analyticsPeriod" type="date"><button class="primary" id="analyticsApply">Применить</button></div>'}
function renderAnalytics(){let root=$('#analyticsContent'); if(!root)return; let tab=state.analyticsTab||'overview', data=analyticsRows(); $('#analyticsRefreshBtn')&&($('#analyticsRefreshBtn').onclick=()=>loadAll(true)); $$('.analytics-tab').forEach(b=>{b.classList.toggle('active',b.dataset.analyticsTab===tab); b.onclick=()=>{state.analyticsTab=b.dataset.analyticsTab; renderAnalytics()}}); if(tab==='overview')renderAnalyticsOverview(root,data); if(tab==='users')renderAnalyticsUsers(root,data); if(tab==='top')renderAnalyticsTop(root,data); if(tab==='materials')renderAnalyticsMaterials(root,data); if(tab==='events')renderAnalyticsEvents(root,data); if(tab==='kb')renderAnalyticsKb(root,data)}
function analyticsStatsHtml(data){let done=state.progress.filter(p=>p.PROPERTY_VALUES.status==='completed').length, inwork=state.assigns.length-done; return '<div class="stats-grid analytics-stats"><div class="dash-stat"><span>Материалов всего</span><b>'+data.materials.length+'</b></div><div class="dash-stat"><span>Пользователей всего</span><b>'+state.users.length+'</b></div><div class="dash-stat"><span>Пройдено материалов</span><b>'+done+'</b></div><div class="dash-stat"><span>Материалов в работе</span><b>'+Math.max(0,inwork)+'</b></div></div>'}
function dateKey(value){let d=value?new Date(value):new Date(); if(isNaN(d))d=new Date(); return d.toISOString().slice(0,10)}
function shortDateLabel(key){let d=new Date(key); return isNaN(d)?key:d.toLocaleDateString('ru-RU',{day:'2-digit',month:'2-digit'})}
function analyticsTrendDays(){let days=[]; for(let i=6;i>=0;i--){let d=new Date(); d.setDate(d.getDate()-i); days.push(d.toISOString().slice(0,10))} return days}
function renderAnalyticsOverview(root,data){let done=state.progress.filter(p=>p.PROPERTY_VALUES.status==='completed').length, assigned=state.assigns.length, opened=state.events.filter(e=>e.PROPERTY_VALUES?.event==='Открытие').length, inwork=Math.max(0,Math.min(assigned-done,opened)), notStarted=Math.max(0,assigned-done-inwork), total=Math.max(assigned,done+inwork+notStarted,1), doneDeg=Math.round(done/total*360), inworkDeg=Math.round(inwork/total*360), pct=assigned?Math.round(done/assigned*100):0, days=analyticsTrendDays(); let trend=days.map(day=>({day,assigned:state.assigns.filter(a=>dateKey(a.DATE_CREATE||a.PROPERTY_VALUES?.createdAt)===day).length,done:state.progress.filter(p=>p.PROPERTY_VALUES?.status==='completed'&&dateKey(p.PROPERTY_VALUES?.completedAt)===day).length,failed:state.attempts.filter(a=>String(a.PROPERTY_VALUES?.passed)==='N'&&dateKey(a.PROPERTY_VALUES?.createdAt)===day).length})); let max=Math.max(1,...trend.flatMap(r=>[r.assigned,r.done,r.failed])); root.innerHTML=analyticsStatsHtml(data)+'<div class="analytics-grid"><div class="dash-card"><h3>Статусы назначений</h3><div class="analytics-donut" title="Пройдено: '+done+'; В процессе: '+inwork+'; Не начато: '+notStarted+'" style="background:conic-gradient(#22c55e 0 '+doneDeg+'deg,#f59e0b '+doneDeg+'deg '+(doneDeg+inworkDeg)+'deg,#94a3b8 '+(doneDeg+inworkDeg)+'deg 360deg)"><div class="analytics-donut-center">'+pct+'%<br><span class="muted">обученность</span></div></div><div class="legend"><span title="Завершенные назначения"><i class="green-dot"></i>Пройдено: '+done+'</span><span title="Есть активность, но нет завершения"><i class="orange-dot"></i>В процессе: '+inwork+'</span><span title="Назначено, но еще не открыто"><i class="gray-dot"></i>Не начато: '+notStarted+'</span></div></div><div class="dash-card"><h3>Тренды за 7 дней</h3><div class="bar-chart">'+trend.map(r=>'<div class="chart-bar" title="'+shortDateLabel(r.day)+': назначено '+r.assigned+', завершено '+r.done+', провалено '+r.failed+'"><span style="height:'+Math.max(3,Math.round(r.assigned/max*210))+'px"></span><span class="green" style="height:'+Math.max(3,Math.round(r.done/max*210))+'px"></span><span class="red" style="height:'+Math.max(3,Math.round(r.failed/max*210))+'px"></span><small>'+shortDateLabel(r.day)+'</small></div>').join('')+'</div><div class="legend"><span title="Новые назначения"><i class="blue-dot"></i>Назначено</span><span title="Завершенные материалы"><i class="green-dot"></i>Завершено</span><span title="Неуспешные попытки тестов"><i class="red-dot"></i>Провалено</span></div></div></div>'}
