function renderAnalyticsUsers(root,data){root.innerHTML=analyticsTopbar('Поиск по пользователям (имя или email)')+'<div class="stats-grid analytics-stats"><div class="dash-stat"><span>Обученность</span><b>'+avg(data.userRows.map(r=>r.pct))+'%</b></div><div class="dash-stat"><span>Пройдено</span><b>'+sum(data.userRows,'done')+'</b></div><div class="dash-stat"><span>Провалено</span><b>0</b></div><div class="dash-stat"><span>В процессе</span><b>'+sum(data.userRows,'inwork')+'</b></div><div class="dash-stat"><span>Не начато</span><b>'+sum(data.userRows,'notStarted')+'</b></div></div><div class="table-card"><table class="admin-table"><thead><tr><th>Пользователь</th><th>Отделы</th><th>Обученность</th><th>Назначено</th><th>Пройдено</th><th>Провалено</th><th>В процессе</th><th>Не начато</th></tr></thead><tbody id="analyticsUserRows"></tbody></table></div>'; bindAnalyticsTools(()=>renderAnalyticsUsers(root,data)); $('#analyticsUserRows').innerHTML=filteredUsers(data).map(r=>'<tr><td><div class="user-cell"><span class="avatar-mini">'+esc(initials(r.u))+'</span><b>'+esc(fullName(r.u))+'</b></div></td><td>'+esc(userDepartments(r.u))+'</td><td>'+r.pct+'%</td><td>'+r.assigned+'</td><td>'+r.done+'</td><td>'+r.failed+'</td><td>'+r.inwork+'</td><td>'+r.notStarted+'</td></tr>').join('')}
function renderAnalyticsTop(root,data){let rows=data.userRows.sort((a,b)=>b.points-a.points); root.innerHTML=analyticsTopbar('Поиск по пользователям (имя или email)')+'<div class="table-card"><table class="admin-table"><thead><tr><th>Место</th><th>Пользователь</th><th>Очки</th><th>Пройдено</th></tr></thead><tbody>'+rows.map((r,i)=>'<tr><td>'+(i+1)+'</td><td>'+esc(fullName(r.u))+'</td><td>'+r.points+'</td><td>'+r.done+'</td></tr>').join('')+'</tbody></table></div>'; bindAnalyticsTools(()=>renderAnalyticsTop(root,data))}
function renderAnalyticsMaterials(root,data){let q=''; root.innerHTML=analyticsTopbar('Поиск по материалам (название)')+'<div class="table-card"><table class="admin-table"><thead><tr><th>Материал</th><th>Тип</th><th>Назначено</th><th>Обученность</th><th>Пройдено</th><th>Провалено</th><th>В процессе</th><th>Не начато</th></tr></thead><tbody id="analyticsMaterialRows"></tbody></table></div>'; bindAnalyticsTools(()=>renderAnalyticsMaterials(root,data)); q=($('#analyticsSearch')?.value||'').toLowerCase(); $('#analyticsMaterialRows').innerHTML=data.materialRows.filter(r=>r.m.NAME.toLowerCase().includes(q)).map(r=>'<tr><td>'+ico(r.m.PROPERTY_VALUES.type)+' <a>'+esc(r.m.NAME)+'</a></td><td><span class="pill gray">'+typeLabel(r.m.PROPERTY_VALUES.type)+'</span></td><td>'+r.assigned+'</td><td>'+r.pct+'%</td><td>'+r.done+'</td><td>0</td><td>'+r.inwork+'</td><td>'+r.notStarted+'</td></tr>').join('')}
