function renderAnalyticsKb(root,data){let arts=activeRows(state.items).filter(i=>i.PROPERTY_VALUES.type==='article'&&i.PROPERTY_VALUES.status==='published'); root.innerHTML=analyticsTopbar('Поиск по базе знаний')+'<div class="table-card"><table class="admin-table"><thead><tr><th>Статья</th><th>Раздел</th><th>Открытий</th><th>Завершений</th></tr></thead><tbody>'+arts.map(a=>'<tr><td>'+esc(a.NAME)+'</td><td>'+esc(spaceLabel(a.PROPERTY_VALUES.space))+'</td><td>'+state.events.filter(e=>String(e.PROPERTY_VALUES.targetId)===String(a.ID)&&e.PROPERTY_VALUES.event==='Открытие').length+'</td><td>'+state.progress.filter(p=>String(p.PROPERTY_VALUES.targetId)===String(a.ID)).length+'</td></tr>').join('')+'</tbody></table></div>'; bindAnalyticsTools(()=>renderAnalyticsKb(root,data))}
function bindAnalyticsTools(render){$('#analyticsSearch')&&($('#analyticsSearch').oninput=render); $('#analyticsFilterBtn')&&($('#analyticsFilterBtn').onclick=()=>$('#analyticsFilterPanel').classList.toggle('hidden')); $('#analyticsApply')&&($('#analyticsApply').onclick=render); $('#analyticsExportBtn')&&($('#analyticsExportBtn').onclick=()=>downloadEventsCsv())}
function sum(rows,key){return rows.reduce((a,r)=>a+(Number(r[key])||0),0)}
function avg(nums){nums=nums.filter(n=>!isNaN(n)); return nums.length?Math.round(nums.reduce((a,b)=>a+b,0)/nums.length):0}

