function folderPath(id){let arr=[], cur=findItem(id), guard=0; while(cur&&String(cur.PROPERTY_VALUES?.parentId||'root')!=='root'&&guard++<20){arr.unshift(cur); cur=findItem(cur.PROPERTY_VALUES.parentId)} if(cur&&id!=='root')arr.unshift(cur); return arr}
