function renderAssignmentPanel(kind){let cfg=assignmentConfig(kind), pane=$(cfg.pane); if(!pane||!cfg.id)return; let rows=targetAssignments(cfg), q=(pane.dataset.assignSearch||'').toLowerCase(), dept=pane.dataset.assignDept||'all'; let users=rows.map(a=>({assign:a,user:userById(a.PROPERTY_VALUES.userId)})).filter(x=>{let u=x.user||{}; let ds=u.UF_DEPARTMENT||[]; if(!Array.isArray(ds))ds=ds?[ds]:[]; return (fullName(u)+' '+(u.EMAIL||'')).toLowerCase().includes(q)&&(dept==='all'||ds.map(String).includes(String(dept)))}); pane.innerHTML='<div class="assignment-card"><div class="assignment-head"><h2>Назначения</h2><button id="'+kind+'AddAssignees">Добавить пользователей</button></div><div class="assign-info">'+(rows.length?'Этим пользователям материал уже назначен.':'Пока нет назначенных пользователей.')+'</div><input id="'+kind+'AssignSearch" placeholder="Фильтр по имени или email" value="'+esc(pane.dataset.assignSearch||'')+'"><select id="'+kind+'AssignDept"><option value="all">Все департаменты</option>'+state.departments.map(d=>'<option value="'+d.ID+'" '+(String(d.ID)===String(dept)?'selected':'')+'>'+esc(d.NAME)+'</option>').join('')+'</select><div class="assignment-table-wrap"><table class="assignment-table"><thead><tr><th><input type="checkbox" disabled></th><th>Пользователь</th><th>Департаменты</th><th>Срок</th></tr></thead><tbody>'+(users.map(x=>'<tr><td><input type="checkbox" disabled checked></td><td><div class="user-cell"><span class="avatar-mini">'+esc(initials(x.user||{}))+'</span><div><b>'+esc(fullName(x.user)||('ID '+x.assign.PROPERTY_VALUES.userId))+'</b><div class="row-sub">'+esc((x.user||{}).EMAIL||'')+'</div></div></div></td><td>'+esc(userDepartments(x.user||{}))+'</td><td>'+(x.assign.PROPERTY_VALUES.dueAt?fmt(x.assign.PROPERTY_VALUES.dueAt):'—')+'</td></tr>').join('')||'<tr><td colspan="4" class="empty-cell">Нет назначений</td></tr>')+'</tbody></table></div></div>'; $('#'+kind+'AddAssignees').onclick=()=>openAssignModal(kind); $('#'+kind+'AssignSearch').oninput=e=>{pane.dataset.assignSearch=e.target.value; renderAssignmentPanel(kind)}; $('#'+kind+'AssignDept').onchange=e=>{pane.dataset.assignDept=e.target.value; renderAssignmentPanel(kind)}}
function pagedAssignmentUsers(kind){let q=($('#assignModalSearch')?.value||'').toLowerCase(), dept=$('#assignModalDept')?.value||'all', page=Number($('#assignModalPage')?.value||0), cfg=assignmentConfig(kind), assigned=assignmentUserIds(cfg); let list=state.users.filter(u=>!assigned.has(String(u.ID))).filter(u=>(fullName(u)+' '+(u.EMAIL||'')).toLowerCase().includes(q)).filter(u=>{let ds=u.UF_DEPARTMENT||[]; if(!Array.isArray(ds))ds=ds?[ds]:[]; return dept==='all'||ds.map(String).includes(String(dept))}); let size=25, pages=Math.max(1,Math.ceil(list.length/size)); page=Math.max(0,Math.min(page,pages-1)); return {list,page,pages,size,rows:list.slice(page*size,page*size+size)}}
function renderAssignModalUsers(kind){let box=$('#assignModalUsers'); if(!box)return; let data=pagedAssignmentUsers(kind); $('#assignModalPage').value=String(data.page); $('#assignModalCounter').textContent='Показано '+(data.list.length?data.page*data.size+1:0)+'–'+Math.min(data.list.length,(data.page+1)*data.size)+' из '+data.list.length; box.innerHTML=data.rows.map(u=>'<label class="assign-user-row"><input type="checkbox" data-assign-pick="'+u.ID+'"><span class="avatar-mini">'+esc(initials(u))+'</span><span><b>'+esc(fullName(u)||('ID '+u.ID))+'</b><span>'+esc(u.EMAIL||'—')+'</span><span>'+esc(userDepartments(u))+'</span></span></label>').join('')||'<div class="empty-cell">Сотрудники не найдены</div>'; $('#assignPrev').disabled=data.page<=0; $('#assignNext').disabled=data.page>=data.pages-1}
function openAssignModal(kind){let cfg=assignmentConfig(kind); if(!cfg.target)return; let text=assignmentDefaultText(cfg); modal('<h2>Назначить пользователям</h2><button class="modal-close" onclick="window.closeModal()">×</button><div class="assign-modal-search"><input id="assignModalSearch" placeholder="Введите email или ФИО для поиска..."><button id="assignModalSearchBtn">Искать</button></div><select id="assignModalDept"><option value="all">Все департаменты</option>'+state.departments.map(d=>'<option value="'+d.ID+'">'+esc(d.NAME)+'</option>').join('')+'</select><input type="hidden" id="assignModalPage" value="0"><div id="assignModalUsers" class="assign-user-list"></div><div class="assign-pager"><span id="assignModalCounter"></span><span><button id="assignPrev">Назад</button><button id="assignNext">Вперёд</button></span></div><div class="assign-options"><h3>Опции назначения</h3><label class="checkline"><input id="assignNotify" type="checkbox"> Отправить уведомление в Bitrix24</label><label class="checkline"><input id="assignCreateTask" type="checkbox"> Создать задачу в Bitrix24</label><label>Крайний срок задачи</label><input id="assignTaskDue" type="datetime-local"><label>Описание задачи</label><textarea id="assignTaskText">'+esc(text)+'</textarea></div><div class="inline-actions right"><button onclick="window.closeModal()">Отмена</button><button class="primary" id="assignModalSave">Назначить</button></div>'); renderAssignModalUsers(kind); $('#assignModalSearch').oninput=()=>{$('#assignModalPage').value='0'; renderAssignModalUsers(kind)}; $('#assignModalSearchBtn').onclick=()=>renderAssignModalUsers(kind); $('#assignModalDept').onchange=()=>{$('#assignModalPage').value='0'; renderAssignModalUsers(kind)}; $('#assignPrev').onclick=()=>{$('#assignModalPage').value=String(Number($('#assignModalPage').value||0)-1); renderAssignModalUsers(kind)}; $('#assignNext').onclick=()=>{$('#assignModalPage').value=String(Number($('#assignModalPage').value||0)+1); renderAssignModalUsers(kind)}; $('#assignModalSave').onclick=()=>saveAssignmentsFromModal(kind)}
async function notifyAssignment(uid,text){try{await call('im.notify.system.add',{USER_ID:uid,MESSAGE:text})}catch(e){console.warn('Bitrix notification failed',e)}}
async function taskAssignment(uid,cfg,due,text){try{let fields={TITLE:'Изучить материал: '+cfg.title,RESPONSIBLE_ID:Number(uid)||uid,DESCRIPTION:text}; if(due)fields.DEADLINE=due; let resp=window.RTMV47?.bitrixCall?await window.RTMV47.bitrixCall('tasks.task.add',{fields}):await call('tasks.task.add',{fields}); let id=resp?.task?.id||resp?.task?.ID||resp?.ID||resp?.id||resp?.result?.task?.id||''; if(!id)throw new Error('Bitrix24 не вернул ID созданной задачи'); return String(id)}catch(e){console.warn('Bitrix task failed',e); let msg=String(e.message||e); toast(msg.includes('insufficient_scope')?'Назначение сохранено. Добавьте право «Задачи» локальному приложению Bitrix24.':'Назначение сохранено, задача Bitrix24 не создана: '+msg); return ''}}
async function saveAssignmentsFromModal(kind){let cfg=assignmentConfig(kind), users=[...$$('[data-assign-pick]:checked')].map(x=>String(x.dataset.assignPick)); if(!users.length)return alert('Выберите сотрудников'); let due=$('#assignTaskDue').value?new Date($('#assignTaskDue').value).toISOString():'', text=$('#assignTaskText').value||assignmentDefaultText(cfg), sendNotify=$('#assignNotify').checked, createTask=$('#assignCreateTask').checked; let already=assignmentUserIds(cfg); for(const uid of users){if(already.has(String(uid)))continue; let taskId=createTask?await taskAssignment(uid,cfg,due,text):''; let aid=await add(E.assigns,'Назначение: '+cfg.title,{targetId:cfg.id,targetType:cfg.targetType,userId:String(uid),dueAt:due,taskId}); state.assigns.unshift({ID:String(aid),NAME:'Назначение: '+cfg.title,PROPERTY_VALUES:{targetId:cfg.id,targetType:cfg.targetType,userId:String(uid),dueAt:due,taskId},DATE_CREATE:now()}); if(sendNotify)await notifyAssignment(uid,text)} await addEvent('Назначение',cfg.target); await persistNow(); closeModal(); renderAssignmentPanel(kind); renderDashboard();}
