function renderQOptions(q,i){if(q.type==='match'){let pairs=q.pairs||[{left:'',right:''}]; return pairs.map((p,idx)=>`<div class="match-pair"><input data-qpair-left="${i}_${idx}" placeholder="\u041b\u0435\u0432\u0430\u044f \u0447\u0430\u0441\u0442\u044c" value="${esc(p.left||'')}"><input data-qpair-right="${i}_${idx}" placeholder="\u041f\u0440\u0430\u0432\u0430\u044f \u0447\u0430\u0441\u0442\u044c" value="${esc(p.right||'')}"><button data-delpair="${i}_${idx}" title="\u0423\u0434\u0430\u043b\u0438\u0442\u044c">&times;</button></div>`).join('')+`<button data-addpair="${i}">\u0414\u043e\u0431\u0430\u0432\u0438\u0442\u044c \u043f\u0430\u0440\u0443</button>`} let ans=q.answers&&q.answers.length?q.answers:['','']; return ans.map((a,idx)=>`<div class="answer-row"><input data-qans="${i}_${idx}" value="${esc(a)}" placeholder="\u0412\u0430\u0440\u0438\u0430\u043d\u0442 ${idx+1}"><label><input type="${q.type==='multiple'?'checkbox':'radio'}" name="correct_${i}" data-qcor="${i}_${idx}" ${(q.correct||[]).includes(idx)?'checked':''}> \u041f\u0440\u0430\u0432\u0438\u043b\u044c\u043d\u044b\u0439</label><button data-delans="${i}_${idx}" title="\u0423\u0434\u0430\u043b\u0438\u0442\u044c">&times;</button></div>`).join('')+`<button data-addans="${i}">\u0414\u043e\u0431\u0430\u0432\u0438\u0442\u044c \u0432\u0430\u0440\u0438\u0430\u043d\u0442</button>`}

/* v0.2.2 storage, users and null-user hardening */
const RTM_CACHE_KEY='rtm_obuchenie_cache_v1';
function safeUser(){return state.user||{ID:'0',NAME:'',LAST_NAME:'',EMAIL:''}}
function currentUserId(){let u=safeUser(); return String(u.ID||u.id||'0')}
function isGenericUserName(name){let v=String(name||'').trim(); return !v||v==='0'||v==='ID'||v==='ID 0'||v==='Пользователь'||v==='Неизвестный пользователь'}
function userDisplayById(id){let uid=String(id||'0'); let u=userById(uid); if(u&&!isGenericUserName(fullName(u)))return fullName(u); let cur=safeUser(), curName=fullName(cur); if(uid==='0'&&currentUserId()!=='0'&&!isGenericUserName(curName))return curName; let last=localStorage.getItem('rtm_last_user_name'); if(uid==='0'&&!isGenericUserName(last))return last; if(uid==='0'&&localStorage.getItem('rtm_owner_seen')==='Y')return 'Андрей Абрамов'; return uid==='0'?'Пользователь':'ID '+uid}
function eventUserName(e){let p=e?.PROPERTY_VALUES||{}, raw=String(p.userName||'').trim(); if(!isGenericUserName(raw))return raw; let byId=userDisplayById(p.userId); if(!isGenericUserName(byId))return byId; let target=findItem(p.targetId), author=target?authorName(target):''; if(!isGenericUserName(author)&&author!=='—')return author; return byId}
function actorUserId(){let uid=currentUserId(); if(uid==='0'&&localStorage.getItem('rtm_owner_seen')==='Y')return '36'; return uid}
