function snapshotData(){let canvas=(state.canvas||[]).map(function(row){let copy=Object.assign({},row),p=Object.assign({},row.PROPERTY_VALUES||{});delete copy.DETAIL_TEXT;delete copy.detailText;if(p.payload&&String(p.payload).length>512)p.payload='';copy.PROPERTY_VALUES=p;return copy});return {projects:state.projects||[],items:state.items||[],assigns:state.assigns||[],progress:state.progress||[],events:state.events||[],attempts:state.attempts||[],roles:state.roles||[],canvas:canvas,updatedAt:now()}}
async function saveSnapshot(){try{let raw=JSON.stringify(snapshotData()), size=45000, chunks=[]; for(let i=0;i<raw.length;i+=size)chunks.push(raw.slice(i,i+size)); let options={}; options[RTM_SNAPSHOT_COUNT]=String(chunks.length); chunks.forEach((chunk,i)=>options[RTM_SNAPSHOT_PREFIX+i]=chunk); await call('app.option.set',{options});}catch(e){console.warn('app.option snapshot save failed',e)}}
