async function createMaterial(type,name,extra={}){try{busy('\u0421\u043E\u0437\u0434\u0430\u044E \u043C\u0430\u0442\u0435\u0440\u0438\u0430\u043B...'); let meta={}; if(type==='course')meta={points:5,certificate:false,sequential:false,passScore:100,sections:[{id:'nosection',title:'\u0411\u0435\u0437 \u0441\u0435\u043A\u0446\u0438\u0438',order:0}]}; if(type==='article')meta={points:1,pages:[{title:'\u041D\u043E\u0432\u0430\u044F \u0441\u0442\u0440\u0430\u043D\u0438\u0446\u0430',html:'<h1>\u041D\u043E\u0432\u0430\u044F \u0441\u0442\u0440\u0430\u043D\u0438\u0446\u0430</h1><p><br></p>'}]}; if(type==='test')meta={questions:[]}; let user=safeUser(); let props={type,status:'draft',projectId:String(state.projectId||''),parentId:String(state.folderId||'root'),space:projectCode(state.projectId),content:type==='article'?'<h1>\u041D\u043E\u0432\u0430\u044F \u0441\u0442\u0440\u0430\u043D\u0438\u0446\u0430</h1><p><br></p>':'',meta:json({...meta,...extra}),author:fullName(user)||'\u041F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u0435\u043B\u044C',authorId:currentUserId(),updatedAt:now()}; let id=await add(E.items,name,props); upsertLocalItem(id,name,props); await persistNow(); addEvent('\u0421\u043E\u0437\u0434\u0430\u043D\u0438\u0435',{ID:id,NAME:name,PROPERTY_VALUES:props}).catch(e=>console.warn(e)); renderDashboard(); renderMaterials(); renderUserCourses(); renderKb(); openItem(id);}catch(e){alert('\u041D\u0435 \u0443\u0434\u0430\u043B\u043E\u0441\u044C \u0441\u043E\u0437\u0434\u0430\u0442\u044C \u043C\u0430\u0442\u0435\u0440\u0438\u0430\u043B: '+e.message)}finally{idle();}}
function projectModal(){modal(`<h2>\u041D\u043E\u0432\u044B\u0439 \u043F\u0440\u043E\u0435\u043A\u0442</h2><input id="projectName" placeholder="\u041D\u0430\u0437\u0432\u0430\u043D\u0438\u0435 \u043F\u0440\u043E\u0435\u043A\u0442\u0430"><div class="inline-actions"><button onclick="window.closeModal()">\u041E\u0442\u043C\u0435\u043D\u0430</button><button class="primary" id="projectCreate">\u0421\u043E\u0437\u0434\u0430\u0442\u044C</button></div>`); $('#projectCreate').onclick=async()=>{let n=$('#projectName').value.trim(); if(!n)return; closeModal(); busy('\u0421\u043E\u0437\u0434\u0430\u044E \u043F\u0440\u043E\u0435\u043A\u0442...'); try{let props={code:slug(n),description:''}; let id=await add(E.projects,n,props); state.projects=state.projects.filter(p=>String(p.ID)!==String(id)); state.projects.unshift({ID:String(id),NAME:n,PROPERTY_VALUES:props,DATE_CREATE:now()}); state.projectId=String(id); await persistNow(); renderAll();}finally{idle();}}}
async function saveRole(uid,role){let existing=state.roles.find(r=>String(r.PROPERTY_VALUES.userId)===String(uid)); let props={userId:String(uid),role,updatedAt:now()}; if(existing){existing.PROPERTY_VALUES=props; await upd(E.roles,existing.ID,'\u0420\u043E\u043B\u044C '+uid,props)} else {let id=await add(E.roles,'\u0420\u043E\u043B\u044C '+uid,props); state.roles.unshift({ID:String(id),NAME:'\u0420\u043E\u043B\u044C '+uid,PROPERTY_VALUES:props,DATE_CREATE:now()})} await persistNow();}
function courseChildren(courseId){return activeRows(state.items).filter(i=>String(i.PROPERTY_VALUES?.parentId)===String(courseId)&&!['section','folder'].includes(i.PROPERTY_VALUES?.type)).sort((a,b)=>(j(a.PROPERTY_VALUES?.meta).order||0)-(j(b.PROPERTY_VALUES?.meta).order||0))}
function continueCourse(){let course=findItem(state.courseId); if(!course)return; let children=courseChildren(course.ID); let next=children.find(m=>!isDone(m.ID,materialKind(m)))||children[0]; if(next)openUserMaterial(next);}
function adjacentMat(dir){let current=$('#userMaterialView')?.dataset.id; let list=courseChildren(state.courseId); let idx=list.findIndex(i=>String(i.ID)===String(current)); let next=list[idx+dir]; if(next)openUserMaterial(next);}
function routeDeepLink(){let p=new URLSearchParams(location.search), kind=p.get('rtm_open'), id=p.get('id')||p.get('course')||p.get('material'); if(!id)return; setMode('user'); if(kind==='course'||p.get('course')){let c=findItem(id); if(c)openUserCourse(c); return;} let m=findItem(id); if(m){if(m.PROPERTY_VALUES.parentId){let c=findItem(m.PROPERTY_VALUES.parentId); if(c)openUserCourse(c)} openUserMaterial(m)}}
if(window.__RTM_V48__)window.__RTM_V48_INIT__=init;
else if(document.readyState==='loading')document.addEventListener('DOMContentLoaded',init);
else init();









function bindRichToolbarGuards(){$$('.format-toolbar').forEach(tb=>{if(tb.dataset.guards)return; tb.dataset.guards='1'; tb.addEventListener('mousedown',e=>{if(e.target.closest('button'))e.preventDefault()})})}

function collectInlineTestSettings(meta){meta=testDefaults(meta||{}); let v=(sel,def)=>document.querySelector(sel)?.value||def; meta.passScore=Number(v('[data-inline-test-pass]',meta.passScore)); meta.attemptsLimit=Number(v('[data-inline-test-attempts]',meta.attemptsLimit)); meta.timeLimit=Number(v('[data-inline-test-time]',meta.timeLimit)); meta.points=Number(v('[data-inline-test-points]',meta.points)); meta.shuffleQuestions=!!document.querySelector('[data-inline-test-shuffle-q]')?.checked; meta.shuffleAnswers=!!document.querySelector('[data-inline-test-shuffle-a]')?.checked; meta.showCorrect=!!document.querySelector('[data-inline-test-show]')?.checked; meta.certificate=!!document.querySelector('[data-inline-test-cert]')?.checked; return meta}

function metaObj(v){if(v&&typeof v==='object')return v; return j(v)}
function articleHtmlFromItem(m){if(!m)return ''; let props=m.PROPERTY_VALUES||{}, meta=metaObj(props.meta), pageParts=[]; if(meta.pages&&meta.pages.length){pageParts=meta.pages.map(p=>unwrapTextValue(p?.html||p?.HTML||p?.content||p?.text||p?.body||p?.value)).filter(isUsefulArticleHtml)} if(pageParts.length)return pageParts.map(plainToHtml).join('<hr>'); let direct=[props.content,props.html,props.text,props.body,props.description,meta.content,meta.html,meta.text,meta.body,meta.description].map(unwrapTextValue).filter(isUsefulArticleHtml); if(direct.length)return plainToHtml(direct[0]); let scanned=scanArticleText({props,meta}); return isUsefulArticleHtml(scanned)?plainToHtml(scanned):''}
function articleContentScore(m){return strip(articleHtmlFromItem(m)).replace(/\s+/g,' ').trim().length}
function localCachedItem(id){try{return (readCache().items||[]).find(x=>String(x.ID)===String(id))}catch{return null}}
function richestArticleItem(m){let id=m?.ID, candidates=[m, id?findItem(id):null, id?localCachedItem(id):null].filter(Boolean), best=candidates[0]||m; for(const c of candidates){if(articleContentScore(c)>articleContentScore(best))best=c} return best||m}
function materialReaderHtml(m){let source=richestArticleItem(m), editorHtml=(String(state.articleId||'')===String(m?.ID||'')?$('#articleContentEditable')?.innerHTML:''); if(isUsefulArticleHtml(editorHtml))return plainToHtml(editorHtml); let html=articleHtmlFromItem(source); if(isUsefulArticleHtml(html))return html; return '<div class="article-empty"><b>Содержимое статьи не найдено.</b><p class="muted">Проверьте, что текст сохранен во вкладке Контент и нажмите Опубликовать. ID материала: '+esc(m?.ID||'')+'</p></div>'}
function currentRichEditor(){let active=document.activeElement; if(active&&active.classList&&active.classList.contains('rich-editor'))return active; if(savedRichRange){let node=savedRichRange.commonAncestorContainer; if(node&&node.nodeType===3)node=node.parentElement; let rich=node&&node.closest?node.closest('.rich-editor'):null; if(rich)return rich;} let inline=document.querySelector('[data-inline-rich]'); if(inline&&inline.offsetParent!==null)return inline; return $('#articleContentEditable')||document.querySelector('.rich-editor')}

function showUserView(view){state.uview=view;document.body.classList.remove('is-busy');if(view!=='learn')document.body.classList.remove('is-reading-article');$$('.toplink').forEach(x=>x.classList.toggle('active',x.dataset.userView===view)); $$('.user-view').forEach(v=>v.classList.remove('active')); $('#user'+cap(view))?.classList.add('active')}

function materialKind(m){let t=m?.PROPERTY_VALUES?.type||''; if(t==='article'||t==='test'||t==='course'||t==='folder'||t==='file')return t; let meta=metaObj(m?.PROPERTY_VALUES?.meta); if(meta.pages||articleContentScore(m)>0||scanArticleText(m?.PROPERTY_VALUES)||scanArticleText(meta))return 'article'; return t||'file'}
function backFromUserMaterial(){if(state.materialBackView==='kb'){showUserView('kb'); $('#userMaterialView')?.classList.add('hidden'); renderKb(); return;} openUserCourse(findItem(state.courseId))}

function switchTestEditorTab(tab){state.testEditorTab=tab; $$('.editor-tab[data-test-editor-tab]').forEach(b=>b.classList.toggle('active',b.dataset.testEditorTab===tab)); $('#testQuestionsEditor')?.classList.toggle('hidden',tab!=='questions'); $('#testTabAssign')?.classList.toggle('active',tab==='assign')}

function bindTestTabs(){$$('.editor-tab[data-test-editor-tab]').forEach(b=>b.onclick=()=>switchTestEditorTab(b.dataset.testEditorTab)); switchTestEditorTab(state.testEditorTab||'questions')}

function unwrapTextValue(v){if(v==null)return ''; if(typeof v==='string')return v; if(Array.isArray(v))return v.map(unwrapTextValue).filter(Boolean).join('<hr>'); if(typeof v==='object'){if(v.TEXT)return unwrapTextValue(v.TEXT); if(v.HTML)return unwrapTextValue(v.HTML); if(v.html)return unwrapTextValue(v.html); if(v.VALUE)return unwrapTextValue(v.VALUE); if(v.value)return unwrapTextValue(v.value); if(v.text)return unwrapTextValue(v.text); if(v.content)return unwrapTextValue(v.content); if(v.body)return unwrapTextValue(v.body)} return ''}

function isUsefulArticleHtml(v){let text=strip(String(v||'')).replace(/\s+/g,' ').trim(); if(!text)return false; let lower=text.toLowerCase(); if(lower==='новая страница')return false; return true}

function plainToHtml(v){v=String(v||''); return /<\/?[a-z][\s\S]*>/i.test(v)?v:esc(v).replace(/\n/g,'<br>')}

function scanArticleText(obj, seen=new Set()){if(!obj||seen.has(obj))return ''; if(typeof obj==='string')return isUsefulArticleHtml(obj)?obj:''; if(Array.isArray(obj)){let parts=obj.map(x=>scanArticleText(x,seen)).filter(Boolean); return parts.join('<hr>')} if(typeof obj!=='object')return ''; seen.add(obj); let ignored=new Set(['id','ID','type','status','projectId','parentId','space','author','authorId','updatedAt','deleted','deletedAt','deletedPath','sectionId','required','order','points','certificate','sequential','questions','passScore','attemptsLimit','timeLimit','shuffleQuestions','shuffleAnswers','showCorrect']); let preferred=['html','HTML','body','BODY','content','CONTENT','text','TEXT','value','VALUE','description','DESCRIPTION']; for(const k of preferred){if(k in obj){let v=unwrapTextValue(obj[k]); if(isUsefulArticleHtml(v))return v}} for(const [k,v] of Object.entries(obj)){if(ignored.has(k))continue; let found=scanArticleText(v,seen); if(found)return found} return ''}
